console.log('Sending a trading signal to the webhook. Curl command:');
let payload = {
symbol: 'EURUSD',
type: 'POSITION_TYPE_BUY',
time: new Date().toISOString(),
volume: 0.1
};
console.log(curl -X POST --header 'Content-Type: application/json' --header 'Accept: application/json' -d '${ JSON.stringify(payload, undefined, 2) }' '${webhook.url}');
