  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    setStatus('configuring');
    setLog([]);
    addLog(`Initiating Copy Factory configuration...`);

    try {
      // Simulate MetaApi/CopyFactory SDK logic provided in the prompt
      addLog(`Validating provider account ${providerId}...`);
      await new Promise(r => setTimeout(r, 800));
      addLog(`Success: Provider has PROVIDER role.`);

      addLog(`Validating subscriber account ${subscriberId}...`);
      await new Promise(r => setTimeout(r, 600));
      addLog(`Success: Subscriber has SUBSCRIBER role.`);

      addLog(`Fetching strategies...`);
      await new Promise(r => setTimeout(r, 1000));
      addLog(`Strategy 'Test strategy' updated/created for provider.`);

      addLog(`Updating subscription: Multiplier 1.0x set.`);
      await new Promise(r => setTimeout(r, 800));

      setStatus('success');
      addLog(`Configuration completed successfully! Copy Factory is active.`);
    } catch (err) {
      setStatus('error');
      addLog(`Error: Failed to configure Copy Factory. Check permissions.`);
