            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Provider Account</label>
            <select 
              value={providerId}
              onChange={(e) => setProviderId(e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none"
            >
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.id})</option>)}
