            status === 'configuring' ? 'bg-slate-800 text-slate-500 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-600/20'
          }`}
        >
          {status === 'configuring' ? <Copy className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          {status === 'configuring' ? 'Deploying Configuration...' : 'Initialize Copy Factory'}
        </button>
