      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-bold text-white uppercase tracking-wider">Deployment Logs</h3>
          {status === 'success' && <div className="flex items-center gap-1 text-emerald-400 text-xs font-bold"><CheckCircle className="w-3 h-3" /> ACTIVE</div>}
          {status === 'error' && <div className="flex items-center gap-1 text-rose-400 text-xs font-bold"><AlertCircle className="w-3 h-3" /> FAILED</div>}
        </div>
        <div className="bg-slate-950 rounded-2xl p-4 h-48 overflow-y-auto font-mono text-xs space-y-2 border border-slate-800">
          {log.length === 0 ? (
            <div className="text-slate-600 italic">No logs to display. Waiting for initialization...</div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={line.includes('Success') || line.includes('completed') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400' : 'text-slate-400'}>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

