  Terminal,
  RefreshCw,
  Play,
  Pause,
  AlertCircle
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // The API key is provided via process.env.API_KEY as per system instructions
      // Using the Provisioning API URL for the London region as specified in the prompt
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        headers: {
          'auth-token': process.env.API_KEY || ''
        }
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.statusText}`);
      }

      const data = await response.json();

      // Transform MetaApi account object to our local TradingAccount type
      const mappedAccounts: TradingAccount[] = data.map((acc: any) => ({
        id: acc._id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: 0, // Balance usually requires a separate streaming or RPC connection
        equity: 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('Failed to fetch MetaApi accounts:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-64 bg-slate-900 border border-slate-800 rounded-3xl p-8 text-center">
