          <p className="text-slate-400 mb-6">{error}</p>
          <button 
            onClick={fetchAccounts}
            className="px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-colors"
          >
            Retry Connection
          </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md">
          <div className="flex items-center gap-4">
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <RefreshCw className="w-4 h-4 animate-spin text-blue-400" />}
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-full text-xs font-medium text-slate-300">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
              MetaApi Server: London Region
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 disabled:opacity-50"
            >
              <RefreshCw className="w-5 h-5" />
            </button>
            <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center font-bold text-sm">
              TR
            </div>
          </div>
        </header>

        {/* Dynamic Content */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {renderContent()}
        </div>

        {/* Footer Status Bar */}
        <footer className="h-10 bg-slate-900 border-t border-slate-800 flex items-center px-8 gap-6 text-[10px] uppercase tracking-wider font-semibold text-slate-500">
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span>
            REST API: ACTIVE
          </div>
          <div className="flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${accounts.length > 0 ? 'bg-emerald-500' : 'bg-slate-600'}`}></span>
            Accounts: {accounts.length}
          </div>
          <div className="ml-auto text-slate-600">
            Last update: {new Date().toLocaleTimeString()}
          </div>
        </footer>
      </main>
    </div>
  );
};

