import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Please select both a provider and a subscriber.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating Copy Factory configuration...`);

    const TOKEN = process.env.API_KEY || '';
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    try {
      // 1. Verify Accounts and Roles
      addLog(`Validating roles via MetaApi...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: { 'auth-token': TOKEN }
      });
      const providerData = await provRes.json();

      if (!providerData.copyFactoryRoles?.includes('PROVIDER')) {
        throw new Error(`Account ${providerId} missing PROVIDER role.`);
      }
      addLog(`Success: Provider verified.`);

      // 2. Setup/Get Strategy
      addLog(`Syncing strategy for provider...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: { 'auth-token': TOKEN }
      });
      const { id: generatedStrategyId } = await strategyIdRes.json();

      await fetch(`${BASE_URL}/users/current/configuration/strategies/${generatedStrategyId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: `Strategy for ${providerData.name}`,
          description: 'Automated via Trispin Meta Automation App',
          accountId: providerId
        })
      });
      addLog(`Strategy created: ${generatedStrategyId}`);

      // 3. Link Subscriber
      addLog(`Linking subscriber ${subscriberId}...`);
      await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: `Subscriber ${subscriberId}`,
          subscriptions: [
            {
              strategyId: generatedStrategyId,
              multiplier: 1
            }
          ]
        })
      });

      setStatus('success');
      addLog(`Configuration completed! Trades from ${providerId} will now copy to ${subscriberId}.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`Error: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-xl">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-12 h-12 bg-indigo-600/20 rounded-2xl flex items-center justify-center">
            <Layers className="text-indigo-500 w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-white">Copy Factory Setup</h2>
            <p className="text-slate-500 text-sm">Automate trade copying using live MetaApi data</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-center mb-8">
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Provider Account</label>
            <select 
              value={providerId}
              onChange={(e) => setProviderId(e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none"
            >
              <option value="">Select Provider...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>

          <div className="flex justify-center">
            <div className="w-10 h-10 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700">
              <ArrowRight className="text-slate-400 w-5 h-5" />
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Subscriber Account</label>
            <select 
              value={subscriberId}
              onChange={(e) => setSubscriberId(e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none"
            >
              <option value="">Select Subscriber...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <button
          onClick={handleConfigure}
          disabled={status === 'configuring' || accounts.length < 2}
          className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all ${
            status === 'configuring' || accounts.length < 2 ? 'bg-slate-800 text-slate-500 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-lg shadow-indigo-600/20'
          }`}
        >
          {status === 'configuring' ? <Copy className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          {status === 'configuring' ? 'Applying Real-time Settings...' : 'Deploy Live Copy Factory'}
        </button>
        {accounts.length < 2 && (
          <p className="text-xs text-rose-400 mt-4 text-center font-medium">At least two accounts are required to configure copying.</p>
        )}
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-bold text-white uppercase tracking-wider">Live SDK Activity</h3>
          {status === 'success' && <div className="flex items-center gap-1 text-emerald-400 text-xs font-bold"><CheckCircle className="w-3 h-3" /> ACTIVE</div>}
          {status === 'error' && <div className="flex items-center gap-1 text-rose-400 text-xs font-bold"><AlertCircle className="w-3 h-3" /> FAILED</div>}
        </div>
        <div className="bg-slate-950 rounded-2xl p-4 h-48 overflow-y-auto font-mono text-[11px] space-y-1 border border-slate-800">
          {log.length === 0 ? (
            <div className="text-slate-600 italic">No activity recorded. Ready for live deployment.</div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={line.includes('Success') || line.includes('completed') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400' : 'text-slate-400'}>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
