import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Use the provided API key from process.env.API_KEY
      const token = process.env.API_KEY || '';

      // MetaApi Provisioning API endpoint
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        headers: {
          'auth-token': token,
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        // Handle specific 401/403 errors which often cause "API Error: " (empty statusText)
        if (response.status === 401) throw new Error("Unauthorized: Invalid API Token.");
        if (response.status === 403) throw new Error("Forbidden: Token lacks required permissions.");

        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `API Error: ${response.status} ${response.statusText}`);
      }

      const data = await response.json();

      // MetaApi returns an array of account objects.
      // Sometimes the array is nested in a 'data' property depending on the specific API version.
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('MetaApi Fetch Error:', err);
      setError(err.message || "An unknown error occurred while fetching accounts.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-64 bg-slate-900 border border-slate-800 rounded-3xl p-8 text-center max-w-2xl mx-auto mt-10">
