            <AlertCircle className="w-8 h-8 text-rose-500" />
          </div>
          <h3 className="text-xl font-bold text-white mb-2">Connection Problem</h3>
          <p className="text-slate-400 mb-6 font-mono text-sm">{error}</p>
          <div className="flex gap-4">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-600/20 flex items-center gap-2"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Try Again
            </button>
          </div>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <RefreshCw className="w-4 h-4 animate-spin text-blue-400" />}
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-full text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500' : 'bg-emerald-500 animate-pulse'}`}></div>
              Gateway: London
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400 disabled:opacity-50"
              title="Refresh Accounts"
            >
              <RefreshCw className="w-5 h-5" />
            </button>
            <div className="w-8 h-8 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center font-bold text-xs text-indigo-400">
              {process.env.API_KEY ? 'API' : '??'}
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {renderContent()}
        </div>

        <footer className="h-10 bg-slate-900 border-t border-slate-800 flex items-center px-8 gap-6 text-[10px] uppercase tracking-wider font-semibold text-slate-500 shrink-0">
          <div className="flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${error ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            Status: {error ? 'Offline' : 'Online'}
          </div>
          <div className="flex items-center gap-2">
            <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span>
            Accounts Synced: {accounts.length}
          </div>
          <div className="ml-auto text-slate-600">
            Node: Meta-SDK-v29.0
          </div>
        </footer>
      </main>
    </div>
