  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    // Note: process.env.API_KEY is automatically populated with the token you provided
    const token = process.env.API_KEY;

    if (!token) {
      setError("MetaApi Token Missing: System environment variable API_KEY is not set.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // Endpoint for MetaTrader account management (Provisioning API)
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401) {
          throw new Error("Unauthorized: The MetaApi token is invalid or expired. Please check the injected token.");
        }
        if (response.status === 403) {
          throw new Error("Forbidden: Token lacks required permissions for Provisioning API.");
