      console.error('MetaApi Sync Error:', err);
      setError(err.message || "Failed to establish secure connection to AgiliumTrade.");
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
