import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Edit3, CheckCircle, Info, Server, ShieldCheck, Activity, Loader2 } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt5',
    login: '',
    password: '',
    server: ''
  });

  const handleCreateAccount = async () => {
    const token = process.env.API_KEY;
    if (!token) return;

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: {
          'auth-token': token,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000
        })
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.message || 'Failed to provision account');
      }

      const newAccount = await response.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id,
        name: newAccount.name,
        platform: newAccount.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);
      setIsAdding(false);
      alert('Account provisioned successfully! Deployment starting...');
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white">Broker Connections</h2>
          <p className="text-slate-500">Manage your deployed MT4/MT5 accounts from the cloud</p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-indigo-600/20"
        >
          <Plus className="w-5 h-5" />
          Add Account
        </button>
      </div>

      {accounts.length === 0 ? (
        <div className="bg-slate-900/50 border-2 border-dashed border-slate-800 rounded-[40px] p-20 text-center">
           <Server className="w-12 h-12 text-slate-700 mx-auto mb-6" />
           <p className="text-slate-500 font-medium">No cloud accounts detected on your MetaApi profile.</p>
           <p className="text-slate-600 text-sm mt-1">Add your broker credentials below to deploy a new cloud node.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {accounts.map(acc => (
            <div key={acc.id} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 relative overflow-hidden group hover:border-indigo-500/40 transition-all">
              <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
