                  <input 
                    type="text" 
                    value={formData.login}
                    onChange={e => setFormData({...formData, login: e.target.value})}
                    placeholder="123456" 
                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Broker Server</label>
                <input 
                  type="text" 
                  value={formData.server}
                  onChange={e => setFormData({...formData, server: e.target.value})}
                  placeholder="e.g. ICMarketsSC-MT5" 
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
