            </p>
            {error}
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry London Cluster Sync
            </button>
            <p className="text-[10px] text-slate-600 uppercase font-black tracking-widest">
              Domain Requirement: agiliumtrade.agiliumtrade.ai
            </p>
          </div>
        </div>
      );
    }

    if (!isLoading && accounts.length === 0 && activeTab === 'dashboard') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center animate-in fade-in zoom-in duration-500 shadow-xl">
          <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center mb-8 border border-indigo-500/20">
