import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // Direct call to the Provisioning API on the explicit London cluster and domain
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401) {
          throw new Error("Domain Lock Alert: Your token is rejected by the London cluster. Please ensure your MetaApi token has access to 'agiliumtrade.agiliumtrade.ai'. Check 'API Access' in your dashboard.");
        }
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Regional Gateway Error: ${response.status}`);
      }

      const data = await response.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('Regional Connection Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center max-w-2xl mx-auto mt-10 animate-in fade-in zoom-in duration-300 shadow-2xl">
          <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center mb-8 border border-rose-500/20">
            <Key className="w-10 h-10 text-rose-500" />
          </div>
          <h3 className="text-2xl font-bold text-white mb-4">London Cluster Authorization Error</h3>
          <div className="text-slate-400 mb-8 font-mono text-sm leading-relaxed bg-slate-950 p-6 rounded-2xl border border-slate-800 break-all text-left">
            <p className="text-rose-400 font-bold mb-2 flex items-center gap-2 text-xs uppercase tracking-widest">
              <AlertCircle className="w-4 h-4" /> Gateway Exception
            </p>
            {error}
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-600/20"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry London Sync
            </button>
            <p className="text-[10px] text-slate-600 uppercase font-black tracking-widest">
              Context: agiliumtrade.agiliumtrade.ai
            </p>
          </div>
        </div>
      );
    }

    if (!isLoading && accounts.length === 0 && activeTab === 'dashboard') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center animate-in fade-in zoom-in duration-500 shadow-xl">
          <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center mb-8 border border-indigo-500/20">
            <Globe className="w-10 h-10 text-indigo-500" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-4 tracking-tight">Connected: London Cluster</h2>
          <p className="text-slate-400 mb-8 max-w-md mx-auto text-center">
            Successfully authenticated via the London gateway using the <strong>agiliumtrade.agiliumtrade.ai</strong> domain.
          </p>
          <button 
            onClick={() => setActiveTab('accounts')}
            className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-3 shadow-xl shadow-indigo-600/20"
          >
            <Plus className="w-5 h-5" />
            Provision Cloud Account
          </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <RefreshCw className="w-4 h-4 animate-spin text-blue-400" />}
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2 bg-slate-800 px-3 py-1.5 rounded-full text-[10px] font-bold text-slate-400 uppercase tracking-tighter border border-slate-700">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-rose-500' : 'bg-emerald-500'}`}></div>
              Cluster: London
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-2 hover:bg-slate-800 rounded-lg transition-colors text-slate-400"
            >
              <RefreshCw className="w-5 h-5" />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {renderContent()}
        </div>

        <footer className="h-10 bg-slate-900 border-t border-slate-800 flex items-center px-8 gap-6 text-[10px] uppercase tracking-wider font-semibold text-slate-500 shrink-0">
          <div className="flex items-center gap-2">
            <span className={`w-1.5 h-1.5 rounded-full ${error ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            Gateway Status: {error ? 'Unauthorized' : 'Connected'}
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-2">
            <Terminal className="w-3 h-3" />
            MetaApi London v29.0
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Edit3, CheckCircle, Info, Server, ShieldCheck, Activity, Loader2 } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt5',
    login: '',
    password: '',
    server: ''
  });

  const handleCreateAccount = async () => {
    const token = process.env.API_KEY;
    if (!token) return;

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: {
          'auth-token': token.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000
        })
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.message || 'Failed to provision account on London Cluster');
      }

      const newAccount = await response.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id,
        name: newAccount.name,
        platform: newAccount.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);
      setIsAdding(false);
      alert('Cloud node provisioning complete. Deploying on London cluster...');
    } catch (err: any) {
      alert(`Provisioning Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-white">Broker Connections</h2>
          <p className="text-slate-500">Cloud nodes deployed on <strong>london.agiliumtrade.ai</strong></p>
        </div>
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-indigo-600/20"
        >
          <Plus className="w-5 h-5" />
          Add Account
        </button>
      </div>

      {accounts.length === 0 ? (
        <div className="bg-slate-900/50 border-2 border-dashed border-slate-800 rounded-[40px] p-20 text-center">
           <Server className="w-12 h-12 text-slate-700 mx-auto mb-6" />
           <p className="text-slate-500 font-medium">No cloud accounts detected on your MetaApi profile.</p>
           <p className="text-slate-600 text-sm mt-1 text-center max-w-sm mx-auto">Add credentials to deploy a new cloud node on the <strong>London cluster</strong> (Domain: agiliumtrade.agiliumtrade.ai).</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {accounts.map(acc => (
            <div key={acc.id} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 relative overflow-hidden group hover:border-indigo-500/40 transition-all">
              <div className="absolute top-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity">
                <div className="flex gap-2">
                  <button className="p-2 bg-slate-800 hover:bg-rose-600 text-slate-400 hover:text-white rounded-lg transition-colors">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>

              <div className="flex gap-6">
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center font-black text-xl shadow-inner ${acc.platform === PlatformType.MT5 ? 'bg-blue-600/10 text-blue-500' : 'bg-purple-600/10 text-purple-500'}`}>
                  {acc.platform.toUpperCase()}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="font-bold text-lg text-white truncate max-w-[200px]">{acc.name}</h3>
                    <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-0.5 rounded-full ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                      {acc.connectionStatus}
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-y-2 mt-4 text-sm">
                    <div className="text-slate-500 font-medium text-xs">Login ID</div>
                    <div className="text-slate-200 font-mono text-xs">{acc.login}</div>
                    <div className="text-slate-500 font-medium text-xs">Cloud ID</div>
                    <div className="text-slate-400 font-mono text-[9px] truncate">{acc.id}</div>
                    <div className="text-slate-500 font-medium text-xs">Cluster</div>
                    <div className="flex items-center gap-1 text-slate-300 text-xs font-bold">
                      <Globe className="w-3 h-3 text-indigo-400" />
                      London
                    </div>
                  </div>
                </div>
              </div>

              <div className="mt-6 pt-6 border-t border-slate-800 flex items-center justify-between">
                <div className="flex items-center gap-2 text-[10px] text-slate-500 uppercase font-bold tracking-widest">
                  <Activity className="w-4 h-4 text-indigo-500" />
                  Synced with agiliumtrade.ai
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {isAdding && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl w-full max-w-lg p-8 animate-in zoom-in-95 duration-200 shadow-2xl">
            <h3 className="text-xl font-bold text-white mb-6 text-center">Provision London Cloud Node</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Display Name</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  placeholder="e.g. MetaTrader London Node" 
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Platform</label>
                  <select 
                    value={formData.platform}
                    onChange={e => setFormData({...formData, platform: e.target.value})}
                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none"
                  >
                    <option value="mt4">MT4</option>
                    <option value="mt5">MT5</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Login ID</label>
                  <input 
                    type="text" 
                    value={formData.login}
                    onChange={e => setFormData({...formData, login: e.target.value})}
                    placeholder="123456" 
                    className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
                  />
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Broker Server</label>
                <input 
                  type="text" 
                  value={formData.server}
                  onChange={e => setFormData({...formData, server: e.target.value})}
                  placeholder="e.g. MetaQuotes-Demo" 
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Broker Password</label>
                <input 
                  type="password" 
                  value={formData.password}
                  onChange={e => setFormData({...formData, password: e.target.value})}
                  placeholder="••••••••" 
                  className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none" 
                />
              </div>
            </div>
            <div className="mt-8 flex gap-4">
              <button 
                disabled={isSubmitting}
                onClick={() => setIsAdding(false)} 
                className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl font-bold transition-colors"
              >
                Cancel
              </button>
              <button 
                disabled={isSubmitting}
                onClick={handleCreateAccount}
                className="flex-1 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-600/20 transition-all flex items-center justify-center gap-2"
              >
                {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
                {isSubmitting ? 'Provisioning...' : 'Deploy to London'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AccountConfig;

