import React, { useState, useEffect, useCallback } from 'react';
import { 
  Activity, 
  Settings, 
  Shield, 
  Layers, 
  Zap, 
  LineChart, 
  Terminal,
  RefreshCw,
  Play,
  Pause,
  AlertCircle,
  Plus,
  Key,
  Globe
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // Use the explicit Provisioning API URL for the agiliumtrade.agiliumtrade.ai domain cluster
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401) {
          throw new Error("Domain Lock Alert: Your token is rejected by the London cluster. Ensure your token is configured for 'agiliumtrade.agiliumtrade.ai' in the MetaApi dashboard.");
        }
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Regional Gateway Error: ${response.status}`);
      }

      const data = await response.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('Regional Connection Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center max-w-2xl mx-auto mt-10 animate-in fade-in zoom-in duration-300 shadow-2xl">
          <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center mb-8 border border-rose-500/20">
            <Key className="w-10 h-10 text-rose-500" />
          </div>
          <h3 className="text-2xl font-bold text-white mb-4">London Cluster Authorization Error</h3>
          <div className="text-slate-400 mb-8 font-mono text-sm leading-relaxed bg-slate-950 p-6 rounded-2xl border border-slate-800 break-all text-left">
            <p className="text-rose-400 font-bold mb-2 flex items-center gap-2 text-xs uppercase tracking-widest">
              <AlertCircle className="w-4 h-4" /> Gateway Exception
            </p>
            {error}
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-600/20"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry London Sync
            </button>
            <p className="text-[10px] text-slate-600 uppercase font-black tracking-widest">
              Context: agiliumtrade.agiliumtrade.ai
            </p>
          </div>
        </div>
      );
    }

    if (!isLoading && accounts.length === 0 && activeTab === 'dashboard') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center animate-in fade-in zoom-in duration-500 shadow-xl">
          <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center mb-8 border border-indigo-500/20">
            <Globe className="w-10 h-10 text-indigo-500" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-4 tracking-tight">Connected: London Cluster</h2>
          <p className="text-slate-400 mb-8 max-w-md mx-auto text-center">
            Successfully authenticated via the London gateway using the <strong>agiliumtrade.agiliumtrade.ai</strong> domain.
          </p>
          <button 
            onClick={() => setActiveTab('accounts')}
            className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-3 shadow-xl shadow-indigo-600/20"
          >
            <Plus className="w-5 h-5" />
            Provision Cloud Account
          </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 border-b border-slate-800 flex items-center justify-between px-8 bg-slate-900/50 backdrop-blur-md shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize">
              {activeTab.replace('-', ' ')}
            </h1>
