import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Provider and Subscriber selection required.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London Region CopyFactory sync (Domain: agiliumtrade.agiliumtrade.ai)...`);

    const TOKEN = process.env.API_KEY || '';
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    try {
      // 1. Verify Accounts via Provisioning API with strict domain routing
      addLog(`Validating Provider roles on London Cluster...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: { 
          'auth-token': TOKEN.trim(),
          'Accept': 'application/json'
        }
      });

      if (!provRes.ok) throw new Error(`Could not reach Provisioning API at agiliumtrade.agiliumtrade.ai (Status: ${provRes.status})`);
      const providerData = await provRes.json();

      if (!providerData.copyFactoryRoles?.includes('PROVIDER')) {
        addLog(`Warning: PROVIDER role not found. Ensure account is configured for CopyFactory.`);
      }
      addLog(`Success: Provider Node Found (${providerData.name})`);

      // 2. Setup Strategy using London Regional URL
      addLog(`Syncing strategy on London cluster...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Accept': 'application/json'
        }
      });

      if (!strategyIdRes.ok) throw new Error(`CopyFactory API unreachable at ${BASE_URL}. Check token domain scope.`);
      const { id: generatedStrategyId } = await strategyIdRes.json();

      const strategyUpdate = await fetch(`${BASE_URL}/users/current/configuration/strategies/${generatedStrategyId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Strategy for ${providerData.name}`,
          description: 'Trispin London Regional Automation',
          accountId: providerId
        })
      });

      if (!strategyUpdate.ok) throw new Error(`Failed to update strategy configuration.`);
      addLog(`Strategy synced: ${generatedStrategyId}`);

      // 3. Link Subscriber
      addLog(`Deploying subscriber logic to London cluster...`);
      const subUpdate = await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Subscriber ${subscriberId}`,
          subscriptions: [
            {
              strategyId: generatedStrategyId,
              multiplier: 1
            }
          ]
        })
      });

      if (!subUpdate.ok) throw new Error(`Failed to deploy subscriber configuration.`);

      setStatus('success');
      addLog(`Deployment complete! Real-time copying active on London Gateway.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`Critical Error: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-2xl">
        <div className="flex items-center gap-4 mb-8">
