            {status === 'error' && <div className="flex items-center gap-1 text-rose-400 text-xs font-black tracking-widest"><AlertCircle className="w-3 h-3" /> FAILED</div>}
          </div>
        </div>
        <div className="bg-slate-950 rounded-2xl p-6 h-56 overflow-y-auto font-mono text-[11px] leading-relaxed border border-slate-800 custom-scrollbar">
          <div className="text-indigo-400/80 mb-2">-- CONTEXT: agiliumtrade.agiliumtrade.ai --</div>
          {log.length === 0 ? (
            <div className="text-slate-700 italic flex items-center gap-2">
              <Terminal className="w-4 h-4" /> Ready for deployment signals.
            </div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={`flex gap-3 ${line.includes('Success') || line.includes('complete') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400 font-bold' : 'text-slate-400'}`}>
                <span className="text-slate-600 select-none">#</span>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

