import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Provider and Subscriber selection required.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London CopyFactory Deployment...`);

    const TOKEN = process.env.API_KEY || '';
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    try {
      // 1. Verify Node Role via London Provisioning API
      addLog(`Connecting to London cluster: agiliumtrade.agiliumtrade.ai...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: { 
          'auth-token': TOKEN.trim(),
          'Accept': 'application/json'
        }
      });

      if (!provRes.ok) throw new Error(`London Gateway rejection. Status: ${provRes.status}`);
      const providerData = await provRes.json();

      if (!providerData.copyFactoryRoles?.includes('PROVIDER')) {
        addLog(`Warning: Master Node needs PROVIDER role assigned.`);
      }
      addLog(`Master Node Verified: ${providerData.name}`);

      // 2. Strategy Setup on London Cluster
      addLog(`Generating Strategy Context on London Gateway...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!strategyIdRes.ok) throw new Error(`CopyFactory Regional API Error. Check domain scope.`);
      const { id: generatedStrategyId } = await strategyIdRes.json();

      const strategyUpdate = await fetch(`${BASE_URL}/users/current/configuration/strategies/${generatedStrategyId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Automation: ${providerData.name}`,
          description: 'Regional Node Sync via Trispin',
          accountId: providerId
        })
      });

      if (!strategyUpdate.ok) throw new Error(`Failed to initialize strategy on cluster.`);
      addLog(`Strategy Synchronized: ${generatedStrategyId}`);

      // 3. Subscriber Attachment
      addLog(`Linking Subscriber Node on London cluster...`);
      const subUpdate = await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Client Node ${subscriberId}`,
          subscriptions: [
            {
              strategyId: generatedStrategyId,
              multiplier: 1
            }
          ]
        })
      });

      if (!subUpdate.ok) throw new Error(`Failed to deploy subscriber linkage.`);

      setStatus('success');
      addLog(`Deployment Complete! Automated copying active on London Gateway.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`Gateway Error: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-8 shadow-2xl">
        <div className="flex items-center gap-4 mb-8">
          <div className="w-12 h-12 bg-indigo-600/20 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Layers className="text-indigo-500 w-6 h-6" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-white tracking-tight">London CopyFactory Deployment</h2>
            <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Infrastructure: London (agiliumtrade.ai)</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-center mb-8 bg-slate-950 p-6 rounded-2xl border border-slate-800">
          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-3 tracking-widest">Master Provider</label>
            <select 
              value={providerId}
              onChange={(e) => setProviderId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none transition-all"
            >
              <option value="">Select Master...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>

          <div className="flex justify-center pt-4 md:pt-0">
            <div className="w-10 h-10 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700 shadow-inner">
              <ArrowRight className="text-slate-400 w-5 h-5" />
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-3 tracking-widest">Slave Subscriber</label>
            <select 
              value={subscriberId}
              onChange={(e) => setSubscriberId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-3 text-white focus:ring-2 focus:ring-indigo-600 outline-none transition-all"
            >
              <option value="">Select Slave...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <button
          onClick={handleConfigure}
          disabled={status === 'configuring' || accounts.length < 2}
          className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-3 transition-all ${
            status === 'configuring' || accounts.length < 2 ? 'bg-slate-800 text-slate-600 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-xl shadow-indigo-600/30 active:scale-[0.98]'
          }`}
        >
          {status === 'configuring' ? <Copy className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          {status === 'configuring' ? 'Deploying to London Cluster...' : 'Activate Regional Copying'}
        </button>
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-3xl p-6 shadow-xl">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">London Gateway Terminal</h3>
          <div className="flex gap-2">
            {status === 'success' && <div className="flex items-center gap-1 text-emerald-400 text-xs font-black tracking-widest"><CheckCircle className="w-3 h-3" /> LIVE</div>}
            {status === 'error' && <div className="flex items-center gap-1 text-rose-400 text-xs font-black tracking-widest"><AlertCircle className="w-3 h-3" /> FAILED</div>}
          </div>
        </div>
        <div className="bg-slate-950 rounded-2xl p-6 h-56 overflow-y-auto font-mono text-[11px] leading-relaxed border border-slate-800 custom-scrollbar">
          <div className="text-indigo-400/80 mb-2">-- DOMAIN: agiliumtrade.agiliumtrade.ai --</div>
          {log.length === 0 ? (
            <div className="text-slate-700 italic flex items-center gap-2">
              <Terminal className="w-4 h-4" /> System ready for deployment.
            </div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={`flex gap-3 ${line.includes('Success') || line.includes('complete') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400 font-bold' : 'text-slate-400'}`}>
                <span className="text-slate-600 select-none">#</span>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default CopyFactoryConfig;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Activity, 
  Settings, 
  Shield, 
  Layers, 
  Zap, 
  LineChart, 
  Terminal,
  RefreshCw,
  Play,
  Pause,
  AlertCircle,
  Plus,
  Key,
  Globe
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // Correct Provisioning API URL for the London region with agiliumtrade.agiliumtrade.ai domain scope
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401) {
          throw new Error("Authorization Denied: Your token is rejected by the London cluster. Please ensure your MetaApi token has access to the 'agiliumtrade.agiliumtrade.ai' domain in your API Access settings.");
        }
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Gateway Connection Error: ${response.status}`);
      }

      const data = await response.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('London Gateway Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center max-w-2xl mx-auto mt-10 animate-in fade-in zoom-in duration-300 shadow-2xl">
          <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center mb-8 border border-rose-500/20">
            <Key className="w-10 h-10 text-rose-500" />
          </div>
          <h3 className="text-2xl font-bold text-white mb-4">Cluster Authentication Alert</h3>
          <div className="text-slate-400 mb-8 font-mono text-sm leading-relaxed bg-slate-950 p-6 rounded-2xl border border-slate-800 break-all text-left">
            <p className="text-rose-400 font-bold mb-2 flex items-center gap-2 text-xs uppercase tracking-widest">
              <AlertCircle className="w-4 h-4" /> Regional Gateway Lock
            </p>
            {error}
          </div>
          <div className="flex flex-col gap-3">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-2 shadow-lg shadow-indigo-600/20"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry London Sync
            </button>
            <p className="text-[10px] text-slate-600 uppercase font-black tracking-widest">
              Domain: agiliumtrade.agiliumtrade.ai
            </p>
          </div>
        </div>
      );
    }

    if (!isLoading && accounts.length === 0 && activeTab === 'dashboard') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center animate-in fade-in zoom-in duration-500 shadow-xl">
          <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center mb-8 border border-indigo-500/20">
            <Globe className="w-10 h-10 text-indigo-500" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-4 tracking-tight">London Cluster Active</h2>
          <p className="text-slate-400 mb-8 max-w-md mx-auto text-center">
            Successfully connected to the London regional gateway. Cloud nodes are active on <strong>agiliumtrade.agiliumtrade.ai</strong>.
          </p>
          <button 
            onClick={() => setActiveTab('accounts')}
            className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-3 shadow-xl shadow-indigo-600/20"
          >
            <Plus className="w-5 h-5" />
            Provision Cloud Account
          </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

