interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt5',
    login: '',
    password: '',
    server: ''
  });

  const handleCreateAccount = async () => {
    const token = process.env.API_KEY;
    if (!token) {
      alert("System Error: API Key not found in environment.");
      return;
    }

    if (!formData.login || !formData.password || !formData.server) {
      alert("Validation Error: Login, Password, and Server Name are mandatory.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: {
          'auth-token': token.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london' // Explicitly targeting London region
        })
      });

      if (!response.ok) {
        const err = await response.json().catch(() => ({ message: 'Regional Gateway rejected the provisioning request.' }));
        throw new Error(err.message || `HTTP ${response.status}: Failed to provision.`);
      }

      const newAccount = await response.json();

      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: newAccount.name,
        platform: newAccount.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setFormData({ name: '', platform: 'mt5', login: '', password: '', server: '' });
      alert('Success! Cloud node provisioned on agiliumtrade.agiliumtrade.ai.');
    } catch (err: any) {
      console.error('Provisioning Error:', err);
