  const handleCreateAccount = async () => {
    const token = process.env.API_KEY;
    if (!token) {
      alert("System Error: API Key not found. Please ensure environment variable is set.");
      return;
    }

    if (!formData.login || !formData.password || !formData.server) {
      alert("Validation Error: Please fill in the Login, Password, and Server Name.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: {
          'auth-token': token.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london'
        })
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          throw new Error("Cluster Domain Lock: Your token does not have 'agiliumtrade.agiliumtrade.ai' added as an allowed domain in the MetaApi dashboard settings.");
        }
        const err = await response.json().catch(() => ({ message: 'Regional Gateway rejected the request.' }));
        throw new Error(err.message || `Status ${response.status}: Failed to provision account.`);
      }

      const newAccount = await response.json();

      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: newAccount.name,
        platform: newAccount.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setFormData({ name: '', platform: 'mt5', login: '', password: '', server: '' });
      alert('Success! Account node provisioned to London cluster.');
    } catch (err: any) {
