          <div className="max-w-2xl mx-auto">
            <div className="flex items-center justify-between mb-12">
              <div className="flex items-center gap-5">
                <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
                  <Shield className="text-indigo-500 w-6 h-6" />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-white tracking-tight">Link Terminal</h3>
                  <p className="text-slate-500 text-sm font-medium">Provisioning resources in London region</p>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="md:col-span-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Internal Node Identifier</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  placeholder="e.g. Master Terminal Alpha" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none transition-all placeholder:text-slate-700 font-bold" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Platform Protocol</label>
                <div className="grid grid-cols-2 gap-4">
                  {['mt4', 'mt5'].map(p => (
                    <button 
                      key={p}
                      onClick={() => setFormData({...formData, platform: p})}
                      className={`py-5 rounded-2xl font-black transition-all border-2 ${
                        formData.platform === p 
                        ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl shadow-indigo-600/20' 
                        : 'bg-slate-950 border-slate-800 text-slate-600 hover:border-slate-700'
                      }`}
                    >
                      {p.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Login Account ID</label>
                <input 
                  type="text" 
                  value={formData.login}
                  onChange={e => setFormData({...formData, login: e.target.value})}
                  placeholder="Numeric login..." 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-mono text-lg" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Exact Broker Server</label>
                <input 
                  type="text" 
                  value={formData.server}
                  onChange={e => setFormData({...formData, server: e.target.value})}
                  placeholder="e.g. IC-Markets-Demo" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-bold" 
                />
              </div>

              <div className="relative">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Master Password</label>
                <div className="relative">
                  <input 
                    type={showPassword ? "text" : "password"} 
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                    placeholder="••••••••" 
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none pr-16 font-mono text-lg" 
                  />
                  <button 
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-600 hover:text-indigo-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-6 h-6" /> : <Eye className="w-6 h-6" />}
                  </button>
                </div>
              </div>
            </div>

            <div className="mt-12 flex items-start gap-6 bg-slate-950 p-8 rounded-[32px] border border-slate-800 shadow-inner">
              <Info className="w-8 h-8 text-indigo-400 shrink-0 mt-0.5" />
              <div className="text-sm text-slate-400 leading-relaxed">
                <p className="font-black text-slate-200 uppercase tracking-widest text-[10px] mb-2">Regional Policy Notification</p>
                Requests are routed via <span className="text-indigo-400 font-mono">london-cluster</span> gateway. Ensure your token domain scope includes <span className="text-white font-mono">agiliumtrade.agiliumtrade.ai</span> or this request will be rejected by the cluster firewall.
              </div>
            </div>

            <div className="mt-12 flex gap-6">
              <button 
                disabled={isSubmitting}
                onClick={() => setIsAdding(false)} 
                className="flex-1 py-5 bg-slate-800 hover:bg-slate-700 text-slate-400 rounded-2xl font-black transition-all uppercase tracking-[0.2em] text-[11px]"
              >
                Cancel
              </button>
              <button 
                disabled={isSubmitting}
                onClick={handleCreateAccount}
                className="flex-[2] py-5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black shadow-2xl shadow-indigo-600/30 transition-all flex items-center justify-center gap-4 disabled:opacity-50 uppercase tracking-[0.2em] text-[11px]"
              >
                {isSubmitting ? (
                  <>
                    <Loader2 className="w-5 h-5 animate-spin" />
                    Synchronizing...
                  </>
                ) : (
                  <>
                    <CheckCircle2 className="w-5 h-5" />
                    Provision Node
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          {accounts.length === 0 ? (
            <div className="lg:col-span-2 bg-slate-900/40 border-2 border-dashed border-slate-800 rounded-[64px] p-32 text-center group">
               <div className="w-24 h-24 bg-slate-800/50 rounded-[40px] flex items-center justify-center mx-auto mb-10 border border-slate-700 group-hover:bg-indigo-600/10 group-hover:border-indigo-500/20 transition-all">
                  <Server className="w-10 h-10 text-slate-700 group-hover:text-indigo-500 transition-colors" />
               </div>
               <h3 className="text-2xl font-bold text-slate-400 mb-4 tracking-tight">No Active Terminals</h3>
               <p className="text-slate-500 text-sm max-w-sm mx-auto leading-relaxed">Your MetaTrader nodes on the London gateway cluster will be displayed here once linked.</p>
            </div>
          ) : (
            accounts.map(acc => (
              <div key={acc.id} className="bg-slate-900 border border-slate-800 p-10 rounded-[48px] hover:border-indigo-500/40 transition-all group relative overflow-hidden shadow-xl hover:shadow-indigo-500/5">
                <div className="absolute top-0 left-0 w-3 h-full bg-slate-800 group-hover:bg-indigo-600 transition-colors"></div>

                <div className="flex items-center justify-between mb-10">
