import React, { useState, useEffect, useCallback } from 'react';
import { 
  Activity, 
  Settings, 
  Shield, 
  Layers, 
  Zap, 
  LineChart, 
  Terminal,
  RefreshCw,
  Play,
  Pause,
  AlertCircle,
  Plus,
  Key,
  Globe,
  ExternalLink,
  Loader2
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // Using the provisioning URL from your API Access list
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          throw new Error("Cluster Domain Lock: Your API token is rejected by the London cluster. To fix this: Log in to MetaApi, go to 'API Access' -> 'API Tokens', edit your token, and ensure 'agiliumtrade.agiliumtrade.ai' is added to the allowed domains list.");
        }
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Regional Gateway Error: ${response.status}`);
      }

      const data = await response.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('London Gateway Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center min-h-[500px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center max-w-3xl mx-auto mt-10 animate-in fade-in zoom-in duration-300 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-rose-500"></div>
          <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center mb-8 border border-rose-500/20">
            <Shield className="w-10 h-10 text-rose-500" />
          </div>
          <h3 className="text-2xl font-bold text-white mb-4 tracking-tight">Access Denied by London Cluster</h3>
          <div className="bg-slate-950 p-8 rounded-3xl border border-slate-800 text-left mb-8 shadow-inner">
            <div className="flex items-center gap-3 mb-4 text-rose-400 font-black text-[10px] uppercase tracking-[0.2em]">
              <AlertCircle className="w-4 h-4" /> Domain Scope Error
            </div>
            <p className="text-slate-300 font-medium leading-relaxed text-sm mb-4">
              {error}
            </p>
            <div className="p-4 bg-indigo-600/5 rounded-xl border border-indigo-500/10 text-xs text-slate-400 italic">
              Verification Site: agiliumtrade.agiliumtrade.ai (London Gateway)
            </div>
          </div>
          <div className="flex flex-wrap justify-center gap-4">
            <button 
              onClick={fetchAccounts}
              className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-500 transition-all flex items-center gap-2 shadow-xl shadow-indigo-600/30"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry Connection
            </button>
            <a 
              href="https://app.metaapi.cloud/api-access" 
              target="_blank" 
