import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Layers, 
  Zap, 
  LineChart, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Globe,
  ExternalLink,
  Loader2
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDomainLocked, setIsDomainLocked] = useState(false);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsDomainLocked(false);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          setIsDomainLocked(true);
          throw new Error("Cluster Domain Lock: Your API token is rejected by the London cluster. To fix this: Log in to MetaApi, go to 'API Access' -> 'API Tokens', edit your token, and ensure 'agiliumtrade.agiliumtrade.ai' is added to the allowed domains list.");
        }
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.message || `Regional Gateway Error: ${response.status}`);
      }

      const data = await response.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      }));

      setAccounts(mappedAccounts);
    } catch (err: any) {
      console.error('London Gateway Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    // If domain is locked but we want to provision, let the user go to the accounts tab
    if (error && activeTab !== 'accounts') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[500px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center max-w-3xl mx-auto mt-10 animate-in fade-in zoom-in duration-300 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-rose-500"></div>
          <div className="w-20 h-20 bg-rose-500/10 rounded-3xl flex items-center justify-center mb-8 border border-rose-500/20">
            <Shield className="w-10 h-10 text-rose-500" />
          </div>
          <h3 className="text-2xl font-bold text-white mb-4 tracking-tight">Access Denied by London Cluster</h3>
          <div className="bg-slate-950 p-8 rounded-3xl border border-slate-800 text-left mb-8 shadow-inner">
            <div className="flex items-center gap-3 mb-4 text-rose-400 font-black text-[10px] uppercase tracking-[0.2em]">
              <AlertCircle className="w-4 h-4" /> Domain Scope Error
            </div>
            <p className="text-slate-300 font-medium leading-relaxed text-sm mb-4">
              {error}
            </p>
            <div className="p-4 bg-indigo-600/5 rounded-xl border border-indigo-500/10 text-xs text-slate-400 italic">
              Verification Site: agiliumtrade.agiliumtrade.ai (London Gateway Cluster)
            </div>
          </div>
          <div className="flex flex-wrap justify-center gap-4">
            <button 
              onClick={() => setActiveTab('accounts')}
              className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-500 transition-all flex items-center gap-2 shadow-xl shadow-indigo-600/30"
            >
              <Plus className="w-4 h-4" />
              Go to Provisioning Form
            </button>
            <a 
              href="https://app.metaapi.cloud/api-access" 
              target="_blank" 
              rel="noopener noreferrer"
              className="px-8 py-4 bg-slate-800 text-slate-300 rounded-2xl font-bold hover:bg-slate-700 transition-all flex items-center gap-2"
            >
              Edit Token Domains
              <ExternalLink className="w-4 h-4" />
            </a>
            <button 
              onClick={fetchAccounts}
              className="px-8 py-4 bg-slate-950 text-slate-400 rounded-2xl font-bold hover:text-white transition-all flex items-center gap-2 border border-slate-800"
            >
              <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
              Retry Fetch
            </button>
          </div>
        </div>
      );
    }

    if (!isLoading && accounts.length === 0 && activeTab === 'dashboard') {
      return (
        <div className="flex flex-col items-center justify-center min-h-[400px] bg-slate-900 border border-slate-800 rounded-[40px] p-12 text-center animate-in fade-in zoom-in duration-500 shadow-xl">
          <div className="w-20 h-20 bg-indigo-600/10 rounded-3xl flex items-center justify-center mb-8 border border-indigo-500/20">
            <Globe className="w-10 h-10 text-indigo-500" />
          </div>
          <h2 className="text-3xl font-bold text-white mb-4 tracking-tight">London Cluster Ready</h2>
          <p className="text-slate-400 mb-8 max-w-md mx-auto text-center leading-relaxed font-medium">
            Infrastructure: <strong>agiliumtrade.agiliumtrade.ai</strong>. Use the provisioning form to add your MetaTrader accounts to the cloud.
          </p>
          <button 
            onClick={() => setActiveTab('accounts')}
            className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all flex items-center gap-3 shadow-xl shadow-indigo-600/20"
          >
            <Plus className="w-5 h-5" />
            Provision New Account
          </button>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${error ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.5)]' : 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]'}`}></div>
              Gateway: London Cluster
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700 active:scale-90"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isDomainLocked ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            Domain Status: {isDomainLocked ? 'Scope Locked' : 'Synchronized'}
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3">
            <Terminal className="w-4 h-4 text-indigo-500" />
            Cluster Node: agiliumtrade.agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

