            <div className="mt-12 flex items-start gap-6 bg-indigo-600/5 p-8 rounded-[32px] border border-indigo-500/10">
              <Info className="w-8 h-8 text-indigo-400 shrink-0 mt-0.5" />
              <div className="text-sm text-slate-400 leading-relaxed">
                <p className="font-black text-slate-200 uppercase tracking-widest text-[10px] mb-2">Infrastructure Note</p>
