                    <p className="text-base font-black text-indigo-400 uppercase tracking-tighter">{acc.state}</p>
                  </div>
                </div>

                <div className="mt-10 flex gap-4">
                   <button 
                    disabled={deployingId === acc.id || acc.state === 'DEPLOYED'}
                    onClick={() => handleDeployAccount(acc.id)}
                    className="flex-1 py-4 bg-indigo-600/10 hover:bg-indigo-600 text-indigo-400 hover:text-white rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all border border-indigo-500/20 flex items-center justify-center gap-2 disabled:opacity-50"
                   >
                      {deployingId === acc.id ? <Loader2 className="w-4 h-4 animate-spin" /> : acc.state === 'DEPLOYED' ? <CheckCircle2 className="w-4 h-4" /> : <Activity className="w-4 h-4" />}
