import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  ExternalLink,
  Loader2,
  Settings,
  LayoutDashboard
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDomainLocked, setIsDomainLocked] = useState(false);

  const fetchAccounts = useCallback(async () => {
    const token = process.env.API_KEY;

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsDomainLocked(false);
    try {
      // Primary Provisioning URL for London Cluster
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        // If we get a 401/403, we note the lock but don't stop the app
        if (response.status === 401 || response.status === 403) {
          setIsDomainLocked(true);
          console.warn("Domain Lock detected. Switching to Manual Setup Mode.");
        } else {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.message || `Regional Gateway Error: ${response.status}`);
        }
      } else {
        const data = await response.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        }));

        setAccounts(mappedAccounts);
      }
    } catch (err: any) {
      console.error('London Gateway Fetch Error:', err);
      // We don't set the global error here to avoid blocking the UI
      setIsDomainLocked(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    // We remove the hard-lock error screen to allow navigation
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            {isDomainLocked && (
              <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 border border-rose-500/20 rounded-xl animate-pulse">
                <AlertCircle className="w-4 h-4 text-rose-500" />
                <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Manual Setup Mode</span>
              </div>
            )}
            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${isDomainLocked ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]' : 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]'}`}></div>
              Cluster: London
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700 active:scale-90"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {isDomainLocked && activeTab === 'dashboard' && accounts.length === 0 && (
            <div className="mb-8 p-6 bg-indigo-600/10 border border-indigo-500/20 rounded-[32px] flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-600/30">
                  <Plus className="text-white w-6 h-6" />
                </div>
                <div>
                  <h4 className="text-white font-bold">Initialize London Cluster</h4>
                  <p className="text-indigo-300/60 text-xs">Your token is locked to the London region. Please manually add your accounts in the Accounts tab.</p>
                </div>
              </div>
              <button 
                onClick={() => setActiveTab('accounts')}
                className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black uppercase tracking-widest rounded-xl transition-all"
              >
                Go to Accounts
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isDomainLocked ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
            Gateway: {isDomainLocked ? 'London (Restricted)' : 'London (Full)'}
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3">
            <Terminal className="w-4 h-4 text-indigo-500" />
            Infrastructure: agiliumtrade.agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Server, Globe, Shield, Info, Eye, EyeOff, AlertCircle, CheckCircle2, ChevronRight, Loader2, Database, Activity } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt4',
    login: '',
    password: '',
    server: ''
  });

  const handleCreateAccount = async () => {
    const token = process.env.API_KEY;
    if (!token) return;

    if (!formData.login || !formData.password || !formData.server) {
      alert("Please enter Login, Password, and Broker Server.");
      return;
    }

    setIsSubmitting(true);
    try {
      // Use the exact London Provisioning Gateway
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: {
          'auth-token': token.trim(),
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name || `Node-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london' 
        })
      });

      if (!response.ok) {
        const err = await response.json().catch(() => ({ message: 'Check if this account already exists or if your token has provisioning rights.' }));
        throw new Error(err.message || `Cluster Error (${response.status})`);
      }

      const newAccount = await response.json();

      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: newAccount.name,
        platform: newAccount.platform === 'mt4' ? PlatformType.MT4 : PlatformType.MT5,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setFormData({ name: '', platform: 'mt4', login: '', password: '', server: '' });
      alert('SUCCESS: Account linked to London Cluster. Now click "Initialize Link" to deploy the node.');
    } catch (err: any) {
      console.error('Provisioning Failed:', err);
      alert(`Provisioning Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    const token = process.env.API_KEY;
    if (!token) return;

    setDeployingId(accountId);
    try {
      // Direct deployment as per your shared curl command
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: {
          'auth-token': token.trim(),
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) throw new Error("Deployment failed on the London cluster.");

      alert("Deployment Started: Terminal is initializing on the London regional node.");

      setAccounts(prev => prev.map(acc => 
        acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc
      ));
    } catch (err: any) {
      alert(`Deployment Error: ${err.message}`);
    } finally {
      setDeployingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex items-center justify-between bg-slate-900 p-10 rounded-[48px] border border-slate-800 shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-6 relative z-10">
          <div className="w-16 h-16 bg-indigo-600/10 rounded-3xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Server className="text-indigo-500 w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white tracking-tight">London Terminals</h2>
            <div className="flex items-center gap-3 mt-2">
              <span className="flex items-center gap-1.5 px-3 py-1 bg-emerald-500/10 text-emerald-400 text-[10px] font-black uppercase tracking-widest rounded-full border border-emerald-500/20">
                <Globe className="w-3 h-3" /> Region: London
              </span>
            </div>
          </div>
        </div>
        {!isAdding && (
          <button 
            onClick={() => setIsAdding(true)}
            className="group relative bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-2xl font-black flex items-center gap-3 transition-all shadow-2xl shadow-indigo-600/30"
          >
            <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" />
            Add London Account
          </button>
        )}
      </header>

      {isAdding ? (
        <div className="bg-slate-900 border border-slate-800 rounded-[48px] p-12 shadow-2xl animate-in zoom-in-95 duration-200">
          <div className="max-w-2xl mx-auto">
            <div className="flex items-center gap-5 mb-12">
              <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
                <Database className="text-indigo-500 w-6 h-6" />
              </div>
              <div>
                <h3 className="text-2xl font-black text-white tracking-tight">Provision Regional Node</h3>
                <p className="text-slate-500 text-sm">Target: mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="md:col-span-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Account Name</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  placeholder="e.g. Master Terminal" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-bold" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {['mt4', 'mt5'].map(p => (
                    <button 
                      key={p}
                      onClick={() => setFormData({...formData, platform: p})}
                      className={`py-5 rounded-2xl font-black transition-all border-2 ${
                        formData.platform === p 
                        ? 'bg-indigo-600 border-indigo-400 text-white' 
                        : 'bg-slate-950 border-slate-800 text-slate-600 hover:border-slate-700'
                      }`}
                    >
                      {p.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">MT Login</label>
                <input 
                  type="text" 
                  value={formData.login}
                  onChange={e => setFormData({...formData, login: e.target.value})}
                  placeholder="Account Number" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-mono text-lg" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Broker Server</label>
                <input 
                  type="text" 
                  value={formData.server}
                  onChange={e => setFormData({...formData, server: e.target.value})}
                  placeholder="e.g. IC-Markets-Live20" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-bold" 
