                  <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 shadow-inner">
                    <p className="text-[10px] font-black text-slate-600 uppercase mb-2 tracking-widest">State</p>
                    <p className="text-base font-black text-indigo-400 uppercase tracking-tighter">{acc.state}</p>
                  </div>
                </div>

                <div className="mt-10 flex gap-4">
                   <button 
                    disabled={deployingId === acc.id || acc.state === 'DEPLOYED'}
                    onClick={() => handleDeployAccount(acc.id)}
                    className="flex-1 py-4 bg-indigo-600/10 hover:bg-indigo-600 text-indigo-400 hover:text-white rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all border border-indigo-500/20 flex items-center justify-center gap-2 disabled:opacity-50"
                   >
                      {deployingId === acc.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Activity className="w-4 h-4" />}
                      {acc.state === 'DEPLOYED' ? 'Active Terminal' : 'Initialize Link'}
                   </button>
                   <button className="p-4 bg-rose-500/5 hover:bg-rose-500 text-rose-500 hover:text-white rounded-2xl transition-all border border-rose-500/10 active:scale-90">
                      <Trash2 className="w-5 h-5" />
                   </button>
                </div>
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

