              <div className="text-sm text-slate-400 leading-relaxed">
                <p className="font-black text-slate-200 uppercase tracking-widest text-[10px] mb-2">Security Notice</p>
                Authorization uses sanitized <span className="text-white font-mono">auth-token</span> headers for the London cluster gateway.
              </div>
