import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Loader2,
  Settings
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDomainLocked, setIsDomainLocked] = useState(false);

  const fetchAccounts = useCallback(async () => {
    const token = (process.env.API_KEY || '').trim();

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsDomainLocked(false);
    try {
      // Use Provisioning API for Account List
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          setIsDomainLocked(true);
          console.warn("London cluster domain lock detected.");
        } else {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.message || `Cluster Error: ${response.status}`);
        }
      } else {
        const data = await response.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        }));

        setAccounts(mappedAccounts);
      }
    } catch (err: any) {
      console.error('London Fetch Failed:', err);
      setIsDomainLocked(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30 font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            {isDomainLocked && (
              <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 border border-rose-500/20 rounded-xl">
                <AlertCircle className="w-4 h-4 text-rose-500" />
                <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Auth Scope Error</span>
              </div>
            )}
            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${isDomainLocked ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
              Cluster: London (agiliumtrade.ai)
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {isDomainLocked && activeTab === 'dashboard' && accounts.length === 0 && (
            <div className="mb-8 p-8 bg-indigo-600/10 border border-indigo-500/20 rounded-[40px] flex items-center justify-between shadow-2xl">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center shadow-lg shadow-indigo-600/30">
                  <Plus className="text-white w-7 h-7" />
                </div>
                <div>
                  <h4 className="text-white font-black text-lg">Initialize Regional Node</h4>
                  <p className="text-indigo-300/60 text-sm">Cluster authorization failed. Proceed to manually add your accounts.</p>
                </div>
              </div>
              <button 
                onClick={() => setActiveTab('accounts')}
                className="px-8 py-4 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all shadow-xl shadow-indigo-600/20"
              >
                Go to Accounts
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isDomainLocked ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
            Gateway: London Cluster
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3">
            <Terminal className="w-4 h-4 text-indigo-500" />
            Node: mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Selection required.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Deploying CopyFactory strategy to London Cluster...`);

    const TOKEN = (process.env.API_KEY || '').trim();
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    try {
      // 1. Verify Master Node
      addLog(`Verifying Provisioning Node ID: ${providerId}`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: { 
          'auth-token': TOKEN,
          'Accept': 'application/json'
        }
      });

      if (!provRes.ok) throw new Error(`London Gateway rejection. Status: ${provRes.status}`);
      const providerData = await provRes.json();

      addLog(`Master Node Verified: ${providerData.name}`);

      // 2. Strategy Setup
      addLog(`Generating Regional Strategy ID...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: { 
          'auth-token': TOKEN,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

