  const [isDomainLocked, setIsDomainLocked] = useState(false);

  const fetchAccounts = useCallback(async () => {
    // Sanitize token: remove whitespace and any potential hidden characters
    const token = (process.env.API_KEY || '').trim().replace(/[\n\r]/g, '');

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsDomainLocked(false);
    try {
      // Use Provisioning API for Account List on London Regional Cluster
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          setIsDomainLocked(true);
          console.warn("London cluster domain lock or invalid token detected.");
        } else {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.message || `Cluster Error: ${response.status}`);
        }
      } else {
        const data = await response.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        }));

        setAccounts(mappedAccounts);
      }
    } catch (err: any) {
      console.error('London Fetch Failed:', err);
      setIsDomainLocked(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
