import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal, Loader2 } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Selection required.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Deploying CopyFactory strategy to London Cluster...`);

    // Strict sanitation for London Cluster
    const TOKEN = (process.env.API_KEY || '').trim().replace(/[\n\r]/g, '');
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    try {
      // 1. Verify Master Node
      addLog(`Verifying Provisioning Node ID: ${providerId}`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: { 
          'auth-token': TOKEN,
          'Accept': 'application/json'
        }
      });

      if (!provRes.ok) throw new Error(`London Gateway rejection. Status: ${provRes.status}`);
      const providerData = await provRes.json();

      addLog(`Master Node Verified: ${providerData.name}`);

      // 2. Strategy Setup
      addLog(`Generating Regional Strategy ID...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: { 
          'auth-token': TOKEN,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!strategyIdRes.ok) throw new Error(`Strategy generation failed. Check domain whitelisting.`);
      const { id: generatedStrategyId } = await strategyIdRes.json();

      const strategyUpdate = await fetch(`${BASE_URL}/users/current/configuration/strategies/${generatedStrategyId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Master: ${providerData.name}`,
          description: 'Regional Node Sync',
          accountId: providerId
        })
      });

      if (!strategyUpdate.ok) throw new Error(`Failed to initialize strategy.`);
      addLog(`Strategy Synchronized: ${generatedStrategyId}`);

      // 3. Subscriber Attachment
      addLog(`Linking Subscriber on London gateway...`);
      const subUpdate = await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: { 
          'auth-token': TOKEN,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: `Slave Node ${subscriberId}`,
          subscriptions: [
            {
              strategyId: generatedStrategyId,
              multiplier: 1
            }
          ]
        })
      });

      if (!subUpdate.ok) throw new Error(`Subscriber deployment failed.`);

      setStatus('success');
      addLog(`Success: Automated copying active on London Cluster.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`Fatal Error: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-10 shadow-2xl">
        <div className="flex items-center gap-5 mb-10">
          <div className="w-14 h-14 bg-indigo-600/20 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Layers className="text-indigo-500 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">London CopyFactory</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-1">Infrastructure: London (agiliumtrade.ai)</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center mb-10 bg-slate-950 p-8 rounded-[32px] border border-slate-800">
          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest">Master Node</label>
            <select 
              value={providerId}
              onChange={(e) => setProviderId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white font-bold outline-none"
            >
              <option value="">Select Master...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>

          <div className="flex justify-center">
            <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700">
              <ArrowRight className="text-indigo-400 w-6 h-6" />
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest">Slave Node</label>
            <select 
              value={subscriberId}
              onChange={(e) => setSubscriberId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white font-bold outline-none"
            >
              <option value="">Select Slave...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <button
          onClick={handleConfigure}
          disabled={status === 'configuring' || accounts.length < 2}
          className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-4 transition-all ${
            status === 'configuring' || accounts.length < 2 ? 'bg-slate-800 text-slate-600' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-xl shadow-indigo-600/30'
          }`}
        >
          {status === 'configuring' ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          {status === 'configuring' ? 'Deploying Strategy...' : 'Activate London Copying'}
        </button>
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-8 shadow-xl">
        <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6">Gateway Logs</h3>
        <div className="bg-slate-950 rounded-[32px] p-8 h-64 overflow-y-auto font-mono text-xs leading-relaxed border border-slate-800 custom-scrollbar shadow-inner">
          <div className="text-indigo-500/50 mb-4 font-black">-- CLUSTER::LONDON_REGION --</div>
          {log.length === 0 ? (
            <div className="text-slate-700 flex items-center gap-3">
              <Terminal className="w-4 h-4 opacity-50" /> System idle. Waiting for deployment.
            </div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={`flex gap-4 mb-2 ${line.includes('Success') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400' : 'text-slate-400'}`}>
                <span className="text-slate-800 select-none">{i+1}</span>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

