import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal, Loader2 } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      addLog("Error: Selection required.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Deploying CopyFactory strategy via Bearer Auth...`);

    // Strict Bearer Format for London Cluster
    const TOKEN = (process.env.API_KEY || '').trim().replace(/[\n\r]/g, '');
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    const getHeaders = () => ({
      'Authorization': `Bearer ${TOKEN}`,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    });

    try {
      // 1. Verify Master Node
      addLog(`Verifying Node ID with Bearer token...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: getHeaders()
      });

      if (!provRes.ok) throw new Error(`Bearer auth rejection on Provisioning Gateway. Status: ${provRes.status}`);
      const providerData = await provRes.json();

      addLog(`Master Node Verified: ${providerData.name}`);

      // 2. Strategy Setup
      addLog(`Generating Regional Strategy ID (London)...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: getHeaders()
      });

      if (!strategyIdRes.ok) throw new Error(`Bearer auth failed on CopyFactory gateway.`);
      const { id: generatedStrategyId } = await strategyIdRes.json();

      const strategyUpdate = await fetch(`${BASE_URL}/users/current/configuration/strategies/${generatedStrategyId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({
          name: `Bearer: ${providerData.name}`,
          description: 'Standardized Node Sync',
          accountId: providerId
        })
      });

      if (!strategyUpdate.ok) throw new Error(`Failed to update strategy configuration.`);
      addLog(`Strategy Synchronized: ${generatedStrategyId}`);

      // 3. Subscriber Attachment
      addLog(`Finalizing London subscriber link...`);
      const subUpdate = await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({
          name: `Slave Node ${subscriberId}`,
          subscriptions: [
            {
              strategyId: generatedStrategyId,
              multiplier: 1
            }
          ]
        })
      });

      if (!subUpdate.ok) throw new Error(`Subscriber link failed.`);

      setStatus('success');
      addLog(`Success: Automated copying active via Bearer Auth.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`Fatal Error: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-10 shadow-2xl">
        <div className="flex items-center gap-5 mb-10">
          <div className="w-14 h-14 bg-indigo-600/20 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Layers className="text-indigo-500 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">London CopyFactory</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-1">Bearer: Standardized Security</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center mb-10 bg-slate-950 p-8 rounded-[32px] border border-slate-800 shadow-inner">
          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest">Master Node</label>
            <select 
              value={providerId}
              onChange={(e) => setProviderId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white font-bold outline-none"
            >
              <option value="">Select Master...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>

          <div className="flex justify-center">
            <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700">
              <ArrowRight className="text-indigo-400 w-6 h-6" />
            </div>
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-widest">Slave Node</label>
            <select 
              value={subscriberId}
              onChange={(e) => setSubscriberId(e.target.value)}
              className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white font-bold outline-none"
            >
              <option value="">Select Slave...</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <button
          onClick={handleConfigure}
          disabled={status === 'configuring' || accounts.length < 2}
          className={`w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-4 transition-all ${
            status === 'configuring' || accounts.length < 2 ? 'bg-slate-800 text-slate-600' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-xl shadow-indigo-600/30'
          }`}
        >
          {status === 'configuring' ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          {status === 'configuring' ? 'Linking Strategy...' : 'Activate Automation'}
        </button>
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-8 shadow-xl">
        <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest mb-6">Regional Logs</h3>
        <div className="bg-slate-950 rounded-[32px] p-8 h-64 overflow-y-auto font-mono text-xs leading-relaxed border border-slate-800 custom-scrollbar shadow-inner">
          <div className="text-blue-500/50 mb-4 font-black">-- AUTH_MODE::BEARER_TOKEN --</div>
          {log.length === 0 ? (
            <div className="text-slate-700 flex items-center gap-3">
              <Terminal className="w-4 h-4 opacity-50" /> Initializing secure connection to London...
            </div>
          ) : (
            log.map((line, i) => (
              <div key={i} className={`flex gap-4 mb-2 ${line.includes('Success') ? 'text-emerald-400' : line.includes('Error') ? 'text-rose-400' : 'text-slate-400'}`}>
                <span className="text-slate-800 select-none">{i+1}</span>
                {line}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default CopyFactoryConfig;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Loader2,
  Settings
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isDomainLocked, setIsDomainLocked] = useState(false);

  const fetchAccounts = useCallback(async () => {
    // Sanitize token: strictly remove whitespace and any potential hidden characters
    const token = (process.env.API_KEY || '').trim().replace(/['"\[\]\n\r]/g, '');

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsDomainLocked(false);
    try {
      // MetaTrader account management API - London Cluster strictly uses 'auth-token' header
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          setIsDomainLocked(true);
          console.warn("London cluster: auth-token rejected. Status:", response.status);
        } else {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.message || `Cluster Error: ${response.status}`);
        }
      } else {
        const data = await response.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        }));

        setAccounts(mappedAccounts);
      }
    } catch (err: any) {
      console.error('London Fetch Failed:', err);
      setIsDomainLocked(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30 font-sans">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            {isDomainLocked && (
              <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 border border-rose-500/20 rounded-xl">
                <AlertCircle className="w-4 h-4 text-rose-500" />
                <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Auth Required</span>
              </div>
            )}
            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${isDomainLocked ? 'bg-amber-500' : 'bg-emerald-500'}`}></div>
              Gateway: London (auth-token)
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar">
          {isDomainLocked && activeTab === 'dashboard' && accounts.length === 0 && (
            <div className="mb-8 p-8 bg-indigo-600/10 border border-indigo-500/20 rounded-[40px] flex items-center justify-between shadow-2xl">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center shadow-lg shadow-indigo-600/30">
                  <Plus className="text-white w-7 h-7" />
                </div>
                <div>
                  <h4 className="text-white font-black text-lg">Header Synchronization</h4>
                  <p className="text-indigo-300/60 text-sm">Cluster requires custom 'auth-token' header. Manual node provisioning recommended.</p>
                </div>
              </div>
              <button 
                onClick={() => setActiveTab('accounts')}
                className="px-8 py-4 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all shadow-xl shadow-indigo-600/20"
              >
                Go to Accounts
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isDomainLocked ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
            Infrastructure: MetaApi v1
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3">
            <Terminal className="w-4 h-4 text-indigo-500" />
            Cluster: london.agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

