import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Server, Globe, Info, Eye, EyeOff, CheckCircle2, Loader2, Database, Activity } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt4',
    login: '',
    password: '',
    server: ''
  });

  // MetaApi Custom Header Generation
  const getHeaders = () => {
    const token = (process.env.API_KEY || '').trim().replace(/['"\[\]\n\r]/g, '');
    return {
      'auth-token': token,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    };
  };

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Missing Required Fields: Login, Password, and Broker Server are mandatory.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          name: formData.name || `London-Node-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london' 
        })
      });

      const data = await response.json().catch(() => ({}));

      if (!response.ok) {
        console.error('Provisioning Error Details:', data);
        throw new Error(data.message || `Auth Failed: Header 'auth-token' may be invalid (Status ${response.status})`);
      }

      const newAccount: TradingAccount = {
        id: data.id || data._id,
        name: data.name,
        platform: data.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
        login: data.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      };

      setAccounts(prev => [...prev, newAccount]);
      setIsAdding(false);
      setFormData({ name: '', platform: 'mt4', login: '', password: '', server: '' });
      alert('SUCCESS: Account provisioned. Header auth-token accepted by London Cluster.');
    } catch (err: any) {
      console.error('API Error:', err);
      alert(`Authorization Error: ${err.message}. Ensure header name is exactly 'auth-token'.`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    setDeployingId(accountId);
    try {
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: getHeaders()
      });

      if (!response.ok) {
        const errData = await response.json().catch(() => ({}));
        throw new Error(errData.message || "Deployment rejected by gateway.");
      }

      alert("Deployment Initiated: Finalizing terminal link on London node.");

      setAccounts(prev => prev.map(acc => 
        acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc
      ));
    } catch (err: any) {
      alert(`Deployment Error: ${err.message}`);
    } finally {
      setDeployingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex items-center justify-between bg-slate-900 p-10 rounded-[48px] border border-slate-800 shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-6 relative z-10">
          <div className="w-16 h-16 bg-emerald-600/10 rounded-3xl flex items-center justify-center border border-emerald-500/20 shadow-inner">
            <Server className="text-emerald-500 w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white tracking-tight">Provisioning Terminal</h2>
            <div className="flex items-center gap-3 mt-2">
              <span className="flex items-center gap-1.5 px-3 py-1 bg-slate-800 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-full border border-slate-700">
                <Globe className="w-3 h-3" /> Region: London Cluster
              </span>
            </div>
          </div>
        </div>
        {!isAdding && (
          <button 
            onClick={() => setIsAdding(true)}
            className="group relative bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-2xl font-black flex items-center gap-3 transition-all shadow-2xl shadow-indigo-600/30"
          >
            <Plus className="w-5 h-5 group-hover:rotate-90 transition-transform" />
            Provision London Node
          </button>
        )}
      </header>

      {isAdding ? (
        <div className="bg-slate-900 border border-slate-800 rounded-[48px] p-12 shadow-2xl animate-in zoom-in-95 duration-200">
          <div className="max-w-2xl mx-auto">
            <div className="flex items-center gap-5 mb-12">
              <div className="p-4 bg-indigo-600/10 rounded-2xl border border-indigo-500/20">
                <Database className="text-indigo-500 w-6 h-6" />
              </div>
              <div>
                <h3 className="text-2xl font-black text-white tracking-tight">Add MetaTrader Terminal</h3>
                <p className="text-slate-500 text-sm font-mono text-[10px] uppercase">gateway: mt-provisioning-api-v1</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="md:col-span-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Display Name</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  placeholder="e.g. IC Markets Master" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-bold" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {['mt4', 'mt5'].map(p => (
                    <button 
                      key={p}
                      onClick={() => setFormData({...formData, platform: p as any})}
                      className={`py-5 rounded-2xl font-black transition-all border-2 ${
                        formData.platform === p 
                        ? 'bg-indigo-600 border-indigo-400 text-white' 
                        : 'bg-slate-950 border-slate-800 text-slate-600'
                      }`}
                    >
                      {p.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Account Number</label>
                <input 
                  type="text" 
                  value={formData.login}
                  onChange={e => setFormData({...formData, login: e.target.value})}
                  placeholder="MT4/5 Login" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-mono text-lg" 
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Broker Server</label>
                <input 
                  type="text" 
                  value={formData.server}
                  onChange={e => setFormData({...formData, server: e.target.value})}
                  placeholder="e.g. IC-Markets-Live20" 
                  className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none font-bold" 
                />
              </div>

              <div className="relative">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Master Password</label>
                <div className="relative">
                  <input 
                    type={showPassword ? "text" : "password"} 
                    value={formData.password}
                    onChange={e => setFormData({...formData, password: e.target.value})}
                    placeholder="Terminal Password" 
                    className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white focus:ring-2 focus:ring-indigo-600 outline-none pr-16 font-mono text-lg" 
                  />
                  <button 
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-600 hover:text-indigo-400 transition-colors"
                  >
                    {showPassword ? <EyeOff className="w-6 h-6" /> : <Eye className="w-6 h-6" />}
                  </button>
                </div>
              </div>
            </div>

            <div className="mt-12 flex items-start gap-6 bg-emerald-600/5 p-8 rounded-[32px] border border-emerald-500/10">
              <Info className="w-8 h-8 text-emerald-400 shrink-0 mt-0.5" />
              <div className="text-sm text-slate-400 leading-relaxed">
                <p className="font-black text-emerald-200 uppercase tracking-widest text-[10px] mb-2">Cluster Protocol</p>
                Sending header <span className="text-white font-mono">auth-token</span> exactly as required by the London agiliumtrade.ai cluster.
              </div>
            </div>

            <div className="mt-12 flex gap-6">
              <button 
                disabled={isSubmitting}
                onClick={() => setIsAdding(false)} 
                className="flex-1 py-5 bg-slate-800 hover:bg-slate-700 text-slate-400 rounded-2xl font-black transition-all"
              >
                Cancel
              </button>
              <button 
                disabled={isSubmitting}
                onClick={handleCreateAccount}
                className="flex-[2] py-5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black shadow-2xl shadow-indigo-600/30 transition-all flex items-center justify-center gap-4"
              >
                {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <CheckCircle2 className="w-5 h-5" />}
                {isSubmitting ? 'Syncing Cluster...' : 'Initialize Node'}
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          {accounts.length === 0 ? (
            <div className="lg:col-span-2 bg-slate-900/40 border-2 border-dashed border-slate-800 rounded-[64px] p-32 text-center group">
               <div className="w-24 h-24 bg-slate-800/50 rounded-[40px] flex items-center justify-center mx-auto mb-10 border border-slate-700">
                  <Server className="w-10 h-10 text-slate-700 group-hover:text-indigo-500 transition-colors" />
               </div>
               <h3 className="text-2xl font-bold text-slate-400 mb-4 tracking-tight">London Infrastructure Idle</h3>
               <p className="text-slate-500 text-sm max-w-sm mx-auto leading-relaxed">Add account details to provision nodes on the regional gateway.</p>
            </div>
          ) : (
            accounts.map(acc => (
              <div key={acc.id} className="bg-slate-900 border border-slate-800 p-10 rounded-[48px] hover:border-indigo-500/40 transition-all group relative overflow-hidden shadow-xl">
