                  </div>
                  <div className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-slate-800 text-slate-500 border-slate-700'}`}>
