import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Loader2,
  Settings
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isAuthFailed, setIsAuthFailed] = useState(false);

  const fetchAccounts = useCallback(async () => {
    // CRITICAL: Strict cleaning of the token to remove any quotes, brackets, or spaces
    const rawToken = process.env.API_KEY || '';
    const token = rawToken.trim().replace(/['"\[\]\n\r\s]/g, '');

    if (!token) {
      setError("Token Missing: System API_KEY not detected.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setIsAuthFailed(false);

    try {
      // Primary Test: Verify User Connectivity on Provisioning API
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Accept': 'application/json',
          'Content-Type': 'application/json'
        }
      });

      if (!response.ok) {
        if (response.status === 401 || response.status === 403) {
          setIsAuthFailed(true);
          console.error("MetaApi Auth Failure: check token validity for London region.");
        } else {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.message || `Gateway Error: ${response.status}`);
        }
      } else {
        const data = await response.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const mappedAccounts: TradingAccount[] = rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        }));

        setAccounts(mappedAccounts);
      }
    } catch (err: any) {
      console.error('Connection Failed:', err);
      setIsAuthFailed(true);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAccounts();
  }, [fetchAccounts]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden selection:bg-indigo-500/30 font-sans text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0 z-20">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            {isAuthFailed && (
              <div className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 border border-rose-500/20 rounded-xl animate-pulse">
                <AlertCircle className="w-4 h-4 text-rose-500" />
                <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Auth Token Invalid</span>
              </div>
            )}
            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${isAuthFailed ? 'bg-rose-500' : 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]'}`}></div>
              MetaApi: London Cluster
            </div>
            <button 
              onClick={fetchAccounts}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700 active:scale-95"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar z-10">
          {isAuthFailed && (
            <div className="mb-8 p-10 bg-rose-950/20 border border-rose-500/20 rounded-[40px] flex items-center justify-between shadow-2xl backdrop-blur-sm">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-rose-500 rounded-3xl flex items-center justify-center shadow-lg shadow-rose-500/30">
                  <AlertCircle className="text-white w-7 h-7" />
                </div>
                <div>
                  <h4 className="text-white font-black text-lg">Authorization Error (London)</h4>
                  <p className="text-rose-300/60 text-sm max-w-xl">
                    The custom <code className="bg-slate-900 px-2 py-0.5 rounded text-white">auth-token</code> header was rejected. 
                    Ensure your token is a Personal API Token and not an Account Access Token.
                  </p>
                </div>
              </div>
              <button 
                onClick={fetchAccounts}
                className="px-8 py-4 bg-slate-800 hover:bg-slate-700 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all border border-slate-700"
              >
                Retry Auth Sync
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0 z-20">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isAuthFailed ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            API Mode: Direct (No Bearer)
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3 font-mono">
            <Terminal className="w-4 h-4 text-indigo-500" />
            GW: mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

