import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Loader2,
  Settings,
  CheckCircle2
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthValid, setIsAuthValid] = useState<boolean | null>(null);
  const [error, setError] = useState<string | null>(null);

  /**
   * NUCLEAR TOKEN SANITIZATION
   * Strips everything: quotes, brackets, 'Bearer', spaces, and newlines.
   * Only the raw alphanumeric token remains.
   */
  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s]/g, '')
              .trim();
  };

  const verifyAndFetch = useCallback(async () => {
    const token = getCleanToken();

    if (!token) {
      setError("API_KEY Missing in Environment");
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // MANDATORY TEST: Verify the token against the London Provisioning Gateway
      // If this fails, the token is incorrect or the header is malformed.
      const authTest = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Content-Type': 'application/json'
        }
      });

      if (!authTest.ok) {
        setIsAuthValid(false);
        throw new Error(`Authentication Failed: ${authTest.status} - Check if token is valid for London.`);
      }

      setIsAuthValid(true);

      // Fetch accounts if auth is verified
      const accResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Content-Type': 'application/json'
        }
      });

      const data = await accResponse.json();
      const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

      setAccounts(rawAccounts.map((acc: any) => ({
        id: acc._id || acc.id,
        name: acc.name,
        platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
        login: acc.login,
        connectionStatus: acc.connectionStatus || 'DISCONNECTED',
        state: acc.state || 'UNDEPLOYED',
        balance: acc.balance || 0,
        equity: acc.equity || 0
      })));

    } catch (err: any) {
      console.error('MetaApi Connection Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    verifyAndFetch();
  }, [verifyAndFetch]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-slate-950 overflow-hidden text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 border-b border-slate-800 flex items-center justify-between px-10 bg-slate-900/50 backdrop-blur-xl shrink-0 z-20">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-500 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            {isAuthValid === true && (
              <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Auth Verified</span>
              </div>
            )}

            <div className="flex items-center gap-3 bg-slate-950/50 px-5 py-2 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-slate-800 shadow-inner">
              <div className={`w-2.5 h-2.5 rounded-full ${isAuthValid === false ? 'bg-rose-500 shadow-[0_0_8px_#f43f5e]' : isAuthValid === true ? 'bg-emerald-500 shadow-[0_0_8px_#10b981]' : 'bg-slate-600'}`}></div>
              Gateway: London
            </div>

            <button 
              onClick={verifyAndFetch}
              disabled={isLoading}
              className="p-3 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent hover:border-slate-700"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar z-10">
          {isAuthValid === false && (
            <div className="mb-8 p-10 bg-rose-950/20 border border-rose-500/20 rounded-[40px] flex items-center justify-between shadow-2xl backdrop-blur-sm">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-rose-500 rounded-3xl flex items-center justify-center shadow-lg shadow-rose-500/30">
                  <AlertCircle className="text-white w-7 h-7" />
                </div>
                <div>
                  <h4 className="text-white font-black text-lg">London Cluster Rejected Token</h4>
                  <p className="text-rose-300/60 text-sm max-w-xl">
                    The <code className="bg-slate-900 px-2 py-0.5 rounded text-white font-mono">auth-token</code> was rejected. 
                    The header must be exactly <span className="text-white">auth-token: TOKEN</span>.
                  </p>
                </div>
              </div>
              <button 
                onClick={verifyAndFetch}
                className="px-8 py-4 bg-slate-800 hover:bg-slate-700 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all border border-slate-700"
              >
                Retry Terminal Sync
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-12 bg-slate-900 border-t border-slate-800 flex items-center px-10 gap-8 text-[10px] uppercase tracking-[0.2em] font-black text-slate-500 shrink-0 z-20">
          <div className="flex items-center gap-3">
            <span className={`w-2 h-2 rounded-full ${isAuthValid === false ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            API Protocol: Custom (auth-token)
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3 font-mono">
            <Terminal className="w-4 h-4 text-indigo-500" />
            London Node: agiliumtrade.ai
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Server, Globe, Info, Eye, EyeOff, CheckCircle2, Loader2, Database, Activity } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt4',
    login: '',
    password: '',
    server: ''
  });

  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s]/g, '')
              .trim();
  };

  const getHeaders = () => ({
    'auth-token': getCleanToken(),
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  });

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Required: Login, Password, Server.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london' 
        })
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.message || `Provisioning Failed: ${response.status}`);

      const newAccount: TradingAccount = {
        id: data.id || data._id,
        name: data.name,
        platform: data.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
        login: data.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      };

      setAccounts(prev => [...prev, newAccount]);
      setIsAdding(false);
      setFormData({ name: '', platform: 'mt4', login: '', password: '', server: '' });
      alert('Node provisioned successfully on London Cluster.');
    } catch (err: any) {
      alert(`Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    setDeployingId(accountId);
    try {
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: getHeaders()
      });

      if (!response.ok) throw new Error("Deployment rejected by gateway.");
      alert("Deployment Started.");
      setAccounts(prev => prev.map(acc => acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc));
    } catch (err: any) {
      alert(`Error: ${err.message}`);
    } finally {
      setDeployingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex items-center justify-between bg-slate-900 p-10 rounded-[48px] border border-slate-800 shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-6 relative z-10">
          <div className="w-16 h-16 bg-blue-600/10 rounded-3xl flex items-center justify-center border border-blue-500/20 shadow-inner">
            <Server className="text-blue-500 w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white tracking-tight">Accounts</h2>
            <div className="flex items-center gap-3 mt-2">
              <span className="flex items-center gap-1.5 px-3 py-1 bg-slate-800 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-full border border-slate-700">
                <Globe className="w-3 h-3" /> Region: London
              </span>
            </div>
          </div>
        </div>
        {!isAdding && (
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-5 rounded-2xl font-black flex items-center gap-3 transition-all shadow-2xl shadow-indigo-600/30"
          >
            <Plus className="w-5 h-5" />
            Provision Node
          </button>
        )}
      </header>

      {isAdding ? (
        <div className="bg-slate-900 border border-slate-800 rounded-[48px] p-12 shadow-2xl animate-in zoom-in-95 duration-200">
          <div className="max-w-2xl mx-auto space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="md:col-span-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Node Name</label>
                <input type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {['mt4', 'mt5'].map(p => (
                    <button key={p} onClick={() => setFormData({...formData, platform: p as any})} className={`py-5 rounded-2xl font-black transition-all border-2 ${formData.platform === p ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}>
                      {p.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Login</label>
                <input type="text" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white outline-none" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Server</label>
                <input type="text" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white outline-none" />
              </div>
              <div className="relative">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Password</label>
                <input type={showPassword ? "text" : "password"} value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full bg-slate-950 border border-slate-800 rounded-2xl px-6 py-5 text-white outline-none" />
              </div>
            </div>
            <div className="flex gap-6">
              <button onClick={() => setIsAdding(false)} className="flex-1 py-5 bg-slate-800 text-slate-400 rounded-2xl font-black transition-all">Cancel</button>
              <button onClick={handleCreateAccount} disabled={isSubmitting} className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl transition-all">
                {isSubmitting ? 'Syncing...' : 'Initialize'}
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          {accounts.map(acc => (
            <div key={acc.id} className="bg-slate-900 border border-slate-800 p-10 rounded-[48px] hover:border-indigo-500/40 transition-all shadow-xl">
              <div className="flex items-center justify-between mb-10">
                <div className="flex items-center gap-6">
                  <div className="w-16 h-16 bg-slate-800 rounded-3xl flex items-center justify-center font-black text-slate-400">{acc.platform.toUpperCase()}</div>
                  <h4 className="font-black text-white text-xl">{acc.name}</h4>
                </div>
                <div className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-slate-800 text-slate-500 border-slate-700'}`}>
                  {acc.connectionStatus}
                </div>
              </div>
              <div className="mt-10 flex gap-4">
                 <button 
                  disabled={deployingId === acc.id || acc.state === 'DEPLOYED'}
                  onClick={() => handleDeployAccount(acc.id)}
                  className="flex-1 py-4 bg-indigo-600/10 hover:bg-indigo-600 text-indigo-400 hover:text-white rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all border border-indigo-500/20 disabled:opacity-50"
                 >
                    {acc.state === 'DEPLOYED' ? 'Online' : 'Link Terminal'}
                 </button>
                 <button className="p-4 bg-rose-500/5 hover:bg-rose-500 text-rose-500 hover:text-white rounded-2xl border border-rose-500/10"><Trash2 className="w-5 h-5" /></button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default AccountConfig;

import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal, Loader2 } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s]/g, '')
              .trim();
  };

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) return;

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London sync...`);

    const TOKEN = getCleanToken();
    const BASE_URL = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    const getHeaders = () => ({
      'auth-token': TOKEN,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    });

    try {
      addLog(`Validating nodes...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: getHeaders()
      });

      if (!provRes.ok) throw new Error(`auth-token rejected (Status: ${provRes.status})`);

      addLog(`Generating Strategy...`);
      const strategyIdRes = await fetch(`${BASE_URL}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: getHeaders()
      });

      const { id: sid } = await strategyIdRes.json();

      await fetch(`${BASE_URL}/users/current/configuration/strategies/${sid}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ name: `Sync-${providerId.slice(-4)}`, accountId: providerId })
      });

      addLog(`Linking Subscriber...`);
      await fetch(`${BASE_URL}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ subscriptions: [{ strategyId: sid, multiplier: 1 }] })
      });

      setStatus('success');
      addLog(`SUCCESS: Copying active.`);
    } catch (err: any) {
      setStatus('error');
      addLog(`ERROR: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-10 shadow-2xl">
        <div className="flex items-center gap-5 mb-10">
          <div className="w-14 h-14 bg-indigo-600/20 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Layers className="text-indigo-500 w-7 h-7" />
          </div>
          <h2 className="text-2xl font-black text-white tracking-tight">Copy Engine</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center mb-10 bg-slate-950 p-8 rounded-[32px] border border-slate-800 shadow-inner">
          <select value={providerId} onChange={(e) => setProviderId(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white outline-none">
            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
          </select>
          <div className="flex justify-center"><ArrowRight className="text-indigo-400 w-6 h-6" /></div>
          <select value={subscriberId} onChange={(e) => setSubscriberId(e.target.value)} className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-4 text-white outline-none">
            {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
          </select>
        </div>

        <button onClick={handleConfigure} disabled={status === 'configuring' || accounts.length < 2} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black shadow-xl">
          {status === 'configuring' ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : 'Start Automation'}
        </button>
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-[40px] p-8 h-64 overflow-y-auto font-mono text-xs text-slate-400 custom-scrollbar shadow-inner">
        {log.map((line, i) => <div key={i} className="mb-1">{line}</div>)}
      </div>
    </div>
  );
};

