import React, { useState, useEffect, useCallback } from 'react';
import { 
  Shield, 
  Terminal,
  RefreshCw,
  AlertCircle,
  Plus,
  Loader2,
  Settings,
  CheckCircle2,
  Lock
} from 'lucide-react';
import { PlatformType, TradingAccount } from './types';
import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthValid, setIsAuthValid] = useState<boolean | null>(null);
  const [error, setError] = useState<string | null>(null);

  /**
   * NUCLEAR TOKEN SANITIZATION
   * Strips everything: quotes, brackets, 'Bearer', spaces, and newlines.
   * Ensures the master API token is passed exactly as required by the headers.
   */
  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
              .trim();
  };

  const verifyAndFetch = useCallback(async () => {
    const token = getCleanToken();

    if (!token) {
      setError("API_KEY Missing");
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // TEST ENDPOINT: Verified gold standard for token validation
      const authTest = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Content-Type': 'application/json'
        }
      });

      if (!authTest.ok) {
        setIsAuthValid(false);
        throw new Error(`Auth Failed (${authTest.status}) - Verify auth-token and London cluster access.`);
      }

      setIsAuthValid(true);

      // Fetch accounts using the verified master token
      const accResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: {
          'auth-token': token,
          'Content-Type': 'application/json'
        }
      });

      if (accResponse.ok) {
        const data = await accResponse.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);
        setAccounts(rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        })));
      }

    } catch (err: any) {
      console.error('MetaApi Gateway Error:', err);
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    verifyAndFetch();
  }, [verifyAndFetch]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
      case 'accounts':
        return <AccountConfig accounts={accounts} setAccounts={setAccounts} />;
      case 'risk':
        return <RiskPanel />;
      case 'automation':
        return <CopyFactoryConfig accounts={accounts} />;
      default:
        return <Dashboard accounts={accounts} isLoading={isLoading} />;
    }
  };

  return (
    <div className="flex h-screen bg-[#05080f] overflow-hidden text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 border-b border-white/5 flex items-center justify-between px-10 bg-slate-900/20 backdrop-blur-2xl shrink-0 z-20">
          <div className="flex items-center gap-4">
            <h1 className="text-2xl font-black bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent capitalize tracking-tight">
              {activeTab.replace('-', ' ')}
            </h1>
            {isLoading && <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />}
          </div>

          <div className="flex items-center gap-5">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-950 border border-white/10 rounded-xl">
              <Lock className="w-3 h-3 text-indigo-400" />
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Header: auth-token</span>
            </div>

            {isAuthValid === true && (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Master Access Online</span>
              </div>
            )}

            <div className="flex items-center gap-3 bg-slate-950/50 px-4 py-1.5 rounded-xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-white/5">
              <div className={`w-2.5 h-2.5 rounded-full ${isAuthValid === false ? 'bg-rose-500 shadow-[0_0_10px_#f43f5e]' : isAuthValid === true ? 'bg-emerald-500 shadow-[0_0_10px_#10b981]' : 'bg-slate-700'}`}></div>
              Cluster: London
            </div>

            <button 
              onClick={verifyAndFetch}
              disabled={isLoading}
              className="p-2.5 hover:bg-white/5 rounded-xl transition-all text-slate-400 hover:text-white border border-transparent active:scale-95"
            >
              <RefreshCw className={`w-5 h-5 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 custom-scrollbar z-10">
          {isAuthValid === false && (
            <div className="mb-8 p-10 bg-rose-500/5 border border-rose-500/20 rounded-[40px] flex items-center justify-between shadow-2xl backdrop-blur-xl">
              <div className="flex items-center gap-6">
                <div className="w-14 h-14 bg-rose-500 rounded-3xl flex items-center justify-center shadow-lg shadow-rose-500/20">
                  <AlertCircle className="text-white w-7 h-7" />
                </div>
                <div>
                  <h4 className="text-white font-black text-lg">Cluster Authentication Failed</h4>
                  <p className="text-rose-300/60 text-sm max-w-xl">
                    The London regional gateway rejected the <code className="bg-slate-950 px-2 py-0.5 rounded text-white font-mono">auth-token</code>. 
                    Ensure your master token is correctly injected without Bearer prefixes.
                  </p>
                </div>
              </div>
              <button 
                onClick={verifyAndFetch}
                className="px-8 py-4 bg-slate-900 hover:bg-slate-800 text-white text-xs font-black uppercase tracking-widest rounded-2xl transition-all border border-white/10"
              >
                Retry Terminal Sync
              </button>
            </div>
          )}
          {renderContent()}
        </div>

        <footer className="h-10 bg-slate-900/50 border-t border-white/5 flex items-center px-10 gap-8 text-[9px] uppercase tracking-[0.3em] font-black text-slate-500 shrink-0 z-20">
          <div className="flex items-center gap-3">
            <span className={`w-1.5 h-1.5 rounded-full ${isAuthValid === false ? 'bg-rose-500' : 'bg-emerald-500'}`}></span>
            Master Token Sync: Active
          </div>
          <div className="ml-auto text-slate-600 flex items-center gap-3 font-mono">
            <Terminal className="w-3.5 h-3.5 text-indigo-500" />
            London agiliumtrade.ai cluster
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Server, Globe, Info, Eye, EyeOff, CheckCircle2, Loader2, Database, Activity } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt4',
    login: '',
    password: '',
    server: ''
  });

  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
              .trim();
  };

  const getHeaders = () => ({
    'auth-token': getCleanToken(),
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  });

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Missing Required Fields (Login, Password, Server).");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 1000,
          region: 'london' 
        })
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.message || `Provisioning failed on London Gateway.`);

      setAccounts(prev => [...prev, {
        id: data.id || data._id,
        name: data.name,
        platform: data.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
        login: data.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setFormData({ name: '', platform: 'mt4', login: '', password: '', server: '' });
      alert('Account linked and nodes provisioning in London.');
    } catch (err: any) {
      alert(`Provisioning Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    setDeployingId(accountId);
    try {
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: getHeaders()
      });

      if (!response.ok) throw new Error("Gateway rejected deployment request.");
      alert("Deployment Started.");
      setAccounts(prev => prev.map(acc => acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc));
    } catch (err: any) {
      alert(`Deployment Error: ${err.message}`);
    } finally {
      setDeployingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex items-center justify-between bg-slate-900/40 p-10 rounded-[40px] border border-white/5 shadow-2xl relative overflow-hidden group">
