            <Server className="text-blue-400 w-8 h-8" />
          </div>
          <div>
            <h2 className="text-3xl font-black text-white tracking-tight">Terminals</h2>
            <div className="flex items-center gap-3 mt-2">
              <span className="flex items-center gap-1.5 px-3 py-1 bg-slate-950 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-full border border-white/5">
                <Globe className="w-3 h-3 text-emerald-500" /> London Gateway (Active)
              </span>
            </div>
          </div>
        </div>
        {!isAdding && (
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black flex items-center gap-3 transition-all shadow-xl shadow-indigo-600/20"
          >
            <Plus className="w-5 h-5" />
            Provision Node
          </button>
