      {isAdding ? (
        <div className="bg-slate-900/40 border border-white/5 rounded-[40px] p-12 shadow-2xl animate-in zoom-in-95 duration-200 backdrop-blur-md">
          <div className="max-w-2xl mx-auto space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="md:col-span-2">
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Node Label</label>
                <input type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="Master Account" className="w-full bg-slate-950 border border-white/10 rounded-xl px-6 py-4 text-white outline-none focus:border-indigo-500 transition-colors" />
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Platform</label>
                <div className="grid grid-cols-2 gap-4">
                  {['mt4', 'mt5'].map(p => (
                    <button key={p} onClick={() => setFormData({...formData, platform: p as any})} className={`py-4 rounded-xl font-black transition-all border ${formData.platform === p ? 'bg-indigo-600 border-indigo-400 text-white' : 'bg-slate-950 border-white/5 text-slate-600'}`}>
                      {p.toUpperCase()}
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase mb-4 tracking-[0.2em]">Account Login</label>
                <input type="text" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} className="w-full bg-slate-950 border border-white/10 rounded-xl px-6 py-4 text-white outline-none" />
