              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-5">
                  <div className="w-14 h-14 bg-slate-800 rounded-2xl flex items-center justify-center font-black text-slate-400 group-hover:bg-indigo-600/20 group-hover:text-indigo-400 transition-all">{acc.platform.toUpperCase()}</div>
                  <div>
                    <h4 className="font-black text-white text-lg tracking-tight">{acc.name}</h4>
                    <p className="text-[10px] text-slate-500 font-mono tracking-tighter uppercase opacity-50">NodeID: {acc.id.slice(-8)}</p>
