                </div>
                <div className="p-4 bg-slate-950/50 rounded-xl border border-white/5">
                   <p className="text-[9px] font-black text-slate-600 uppercase mb-1 tracking-widest">State</p>
                   <p className="text-sm font-black text-indigo-400 uppercase tracking-tight">{acc.state}</p>
