const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthValid, setIsAuthValid] = useState<boolean | null>(null);

  /**
   * REFINED MASTER TOKEN SCRUBBER
   * Using the provided JWT Master Token with full API permissions
   */
  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
              .trim();
  };

  const verifyAndFetch = useCallback(async () => {
    const token = getCleanToken();
    if (!token) return;

    setIsLoading(true);

    try {
      // PROVISIONING GATEWAY (London Cluster)
      const authTest = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current', {
        method: 'GET',
        headers: { 'auth-token': token, 'Content-Type': 'application/json' }
      });

      if (!authTest.ok) {
        setIsAuthValid(false);
        throw new Error(`Auth Failed (${authTest.status})`);
      }

      setIsAuthValid(true);

      // Fetch all trading accounts
      const accResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: { 'auth-token': token, 'Content-Type': 'application/json' }
      });

      if (accResponse.ok) {
        const data = await accResponse.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        // Enhance accounts with real-time balance if available
        setAccounts(rawAccounts.map((acc: any) => ({
          id: acc._id || acc.id,
          name: acc.name,
          platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
          login: acc.login,
          connectionStatus: acc.connectionStatus || 'DISCONNECTED',
          state: acc.state || 'UNDEPLOYED',
          balance: acc.balance || 0,
          equity: acc.equity || 0
        })));
      }
    } catch (err) {
      console.error('Master Node Error:', err);
    } finally {
      setIsLoading(false);
    }
