const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    platform: 'mt4',
    login: '',
    password: '',
    server: ''
  });

  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
              .trim();
  };

  const getHeaders = () => ({
    'auth-token': getCleanToken(),
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  });

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Please fill MT4 login, password, and server.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          name: formData.name || `EA-Node-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform,
          magic: 010101,
          region: 'london',
          // AUTOMATED EA DEPLOYMENT PAYLOAD
          expertAdvisor: {
            name: 'TRISPIN-ICT-SCALPER',
            code: TRISPIN_EA_CODE,
            autoStart: true,
            parameters: {
              MagicNumber: 010101,
              symbol: "XAUUSD.m",
              takeprofit: 13000,
              stoploss: 5000
            }
          }
        })
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.message || `Provisioning failed.`);

      setAccounts(prev => [...prev, {
        id: data.id || data._id,
        name: data.name,
        platform: data.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
        login: data.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      alert('Account linked! TRISPIN EA is being compiled in the London Cloud.');
    } catch (err: any) {
      alert(`Provisioning Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    setDeployingId(accountId);
    try {
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: getHeaders()
      });
      if (!response.ok) throw new Error("Deployment rejected.");
      alert("MetaApi Cloud Terminal Initialized.");
      setAccounts(prev => prev.map(acc => acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc));
    } catch (err: any) {
      alert(`Error: ${err.message}`);
    } finally {
      setDeployingId(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <header className="flex items-center justify-between bg-white/5 p-8 rounded-[40px] border border-white/5 shadow-2xl backdrop-blur-md">
