          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Terminal</h2>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-1">Status: London Cluster Online</p>
          </div>
        </div>
        {!isAdding && (
          <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black flex items-center gap-3 transition-all">
            <Plus className="w-5 h-5" /> Provision EA Node
          </button>
        )}
      </header>

      {isAdding ? (
        <div className="bg-slate-900/40 border border-white/5 rounded-[40px] p-10 shadow-2xl animate-in zoom-in-95 backdrop-blur-xl">
          <div className="max-w-xl mx-auto space-y-8">
