              <Zap className="text-indigo-400 w-5 h-5" />
              <p className="text-[10px] font-bold text-indigo-200/70 uppercase">TRISPIN-ICT-SCALPER will be injected automatically</p>
            </div>

            <div className="grid grid-cols-1 gap-6">
              <input type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="Terminal Name" className="w-full bg-slate-950 border border-white/10 rounded-xl px-6 py-4 text-white" />
