            <p className="text-[10px] font-black text-slate-500 uppercase">Gateway: agiliumtrade.ai</p>
          </div>
        </div>
        {!isAdding && (
          <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all">
            + Provision Terminal
          </button>
        )}
      </div>

      {isAdding && (
        <div className="bg-slate-900 border border-white/10 rounded-[40px] p-10 max-w-xl mx-auto shadow-2xl">
          <div className="space-y-6">
            <div className="bg-indigo-500/10 p-4 rounded-xl border border-indigo-500/20 flex items-center gap-3">
              <Zap className="text-indigo-400 w-4 h-4" />
              <span className="text-[10px] font-bold text-indigo-200">EA: TRISPIN-ICT-SCALPER INJECTION ACTIVE</span>
