const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    return raw.replace(/bearer/gi, '').replace(/['"\[\]\n\r\s\t]/g, '').trim();
  };

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) return;

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London cluster sync...`);

    const TOKEN = getCleanToken();
    const COPYFACTORY_BASE = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    const getHeaders = () => ({
      'auth-token': TOKEN, // Strictly 'auth-token'
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    });

    try {
      addLog(`Validating Provider...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: getHeaders()
      });

      if (!provRes.ok) throw new Error(`Auth Error: Token rejected by provisioning.`);

      addLog(`Generating Strategy Node...`);
      const strategyIdRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: getHeaders()
      });

      const strategyData = await strategyIdRes.json();
      const sid = strategyData.id || strategyData._id;

      await fetch(`${COPYFACTORY_BASE}/users/current/configuration/strategies/${sid}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ name: `CF-Sync-${providerId.slice(-4)}`, accountId: providerId })
      });

      addLog(`Attaching Subscriber...`);
      const subRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ 
          name: `Sub-${subscriberId.slice(-4)}`,
          subscriptions: [{ strategyId: sid, multiplier: 1 }] 
        })
      });

      if (!subRes.ok) throw new Error("CopyFactory rejected subscriber attachment.");

      setStatus('success');
      addLog(`SUCCESS: Sync active on London Cluster.`);
    } catch (err: any) {
      setStatus('error');
      addLog(`FATAL: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
