  /**
   * STRICT AUTH-TOKEN RESOLVER
   * Ensures the token is a raw string without any wrapper artifacts.
   */
  const getCleanToken = () => {
    const raw = process.env.API_KEY || '';
    // Removes 'Bearer', whitespace, quotes, and newlines
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
              .trim();
  };

  const verifyAndFetch = useCallback(async () => {
    const token = getCleanToken();
    if (!token) return;

    setIsLoading(true);

    try {
      // PROVISIONING GATEWAY - Primary Auth Check
      const authTest = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current', {
        method: 'GET',
        headers: { 
          'auth-token': token,
          'Accept': 'application/json'
        }
      });

      if (!authTest.ok) {
        setIsAuthValid(false);
        console.error("Master Token Rejected: Check auth-token format in headers.");
        return;
      }

      setIsAuthValid(true);

      // Fetch accounts from Provisioning API
      const accResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: { 'auth-token': token }
      });

      if (accResponse.ok) {
        const data = await accResponse.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        // Map accounts with real-time London Client API metrics
        const enhancedAccounts = await Promise.all(rawAccounts.map(async (acc: any) => {
          let balance = acc.balance || 0;
          let equity = acc.equity || 0;

          if (acc.state === 'DEPLOYED' && acc.connectionStatus === 'CONNECTED') {
