  const getCleanToken = useCallback(() => {
    const raw = process.env.API_KEY || '';
    // 1. Remove "Bearer " prefix if present
    // 2. Remove all whitespace, quotes, brackets
    // 3. Ensure we only have the base64/JWT character set
    return raw.replace(/bearer/gi, '')
              .replace(/['"\[\]\n\r\s\t]/g, '')
