input ENUM_APPLIED_PRICE macdApplyTo = PRICE_CLOSE;
input string symbol = "XAUUSD.m";
input ENUM_TIMEFRAMES timeframe = PERIOD_M15;
string pairs[] = {"XAUUSD.m"};
input int MagicNumber = 010101;
input int ImageWidth = 200;
input int ImageHeight = 200;
input string imageName = "richfield_license.bmp";

void fetch_market_data(string &symbols[]) {
    int totalBars = 100;
    for (int i = 0; i < ArraySize(symbols); i++) {
        for (int j = 0; j < totalBars; j++) {
            TimeCurrent();
        }
    }
}

string ErrorDescription(int code) {
    switch(code) {
        case 1: return "No error";
        case 133: return "Closed";
        case 135: return "No money";
        default: return "Error";
    }
}

int count_open_positions() {
    int count = 0;
    for (int i = 0; i < OrdersTotal(); i++) {
        if (OrderSelect(i, SELECT_BY_POS, MODE_TRADES)) {
            if (OrderSymbol() == Symbol() && OrderMagicNumber() == MagicNumber) count++;
        }
    }
    return count;
}

bool apply_ict_strategy() {
    double tenkanSen = iIchimoku(Symbol(), Period(), ICT_tenkan_period, ICT_kijun_period, ICT_senkou_period, MODE_TENKANSEN, 0);
    double kijunSen = iIchimoku(Symbol(), Period(), ICT_tenkan_period, ICT_kijun_period, ICT_senkou_period, MODE_KIJUNSEN, 0);
    return (tenkanSen > kijunSen);
}

bool apply_smc_strategy() {
    double shortMA = iMA(Symbol(), Period(), SMC_short_MA_period, 0, MODE_SMA, PRICE_CLOSE, 0);
    double longMA = iMA(Symbol(), Period(), SMC_long_MA_period, 0, MODE_SMA, PRICE_CLOSE, 0);
    return (shortMA > longMA);
}

bool apply_sma_strategy() {
    double smaFast = iMA(Symbol(), Period(), smaFastPeriod, 0, MODE_SMA, PRICE_CLOSE, 0);
    double smaSlow = iMA(Symbol(), Period(), smaSlowPeriod, 0, MODE_SMA, PRICE_CLOSE, 0);
    return (smaFast > smaSlow);
}

bool apply_macd_strategy() {
    double macdLine = iMACD(Symbol(), Period(), macdFastEMA, macdSlowEMA, macdSignalSMA, macdApplyTo, MODE_MAIN, 0);
    double signalLine = iMACD(Symbol(), Period(), macdFastEMA, macdSlowEMA, macdSignalSMA, macdApplyTo, MODE_SIGNAL, 0);
    return (macdLine > signalLine);
}

void open_buy_trade() {
    OrderSend(Symbol(), OP_BUY, position_size_min, Ask, Slippage, Ask-stoploss*Point, Ask+takeprofit*Point, position_name, MagicNumber, 0, Blue);
}

void open_sell_trade() {
    OrderSend(Symbol(), OP_SELL, position_size_min, Bid, Slippage, Bid+stoploss*Point, Bid-takeprofit*Point, position_name, MagicNumber, 0, clrRed);
}

void execute_trades() {
    int buy = 0; int sell = 0;
    if (apply_ict_strategy()) buy++; else sell++;
    if (apply_smc_strategy()) buy++; else sell++;
    if (apply_sma_strategy()) buy++; else sell++;
    if (apply_macd_strategy()) buy++; else sell++;
    if (count_open_positions() < NumberOfPositions) {
        if (buy > sell) open_buy_trade();
        else if (sell > buy) open_sell_trade();
    }
}

int OnInit() { return INIT_SUCCEEDED; }
void OnTick() { execute_trades(); }
`;

