    const token = raw.replace(/bearer/gi, '').replace(/['"\[\]\n\r\s\t]/g, '').trim();
    return {
      'auth-token': token, // Standardized lowercase key
      'Accept': 'application/json',
      'Content-Type': 'application/json'
