import Dashboard from './components/Dashboard';
import Sidebar from './components/Sidebar';
import AccountConfig from './components/AccountConfig';
import RiskPanel from './components/RiskPanel';
import CopyFactoryConfig from './components/CopyFactoryConfig';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [accounts, setAccounts] = useState<TradingAccount[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isAuthValid, setIsAuthValid] = useState<boolean | null>(null);

  /**
   * RAW TOKEN RESOLVER
   * Uses the token exactly as provided in the environment.
   * Do NOT use regex replace as it can corrupt the RSA signature parts (dots/underscores).
   */
  const getRawToken = useCallback(() => {
    return (process.env.API_KEY || '').trim();
  }, []);

  const verifyAndFetch = useCallback(async () => {
    const token = getRawToken();
    if (!token) {
      console.warn("No API_KEY detected in process.env");
      return;
    }

    setIsLoading(true);

    try {
      // Use the global provisioning gateway for the initial auth check
      const authTest = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current', {
        method: 'GET',
        headers: { 
          'auth-token': token,
          'Accept': 'application/json'
        }
      });

      if (!authTest.ok) {
        setIsAuthValid(false);
        const errData = await authTest.json().catch(() => ({}));
        console.error("Auth Header Rejected:", errData.message || authTest.statusText);
        console.debug("Token start check:", token.substring(0, 15) + "...");
        return;
      }

      setIsAuthValid(true);

      // Fetch accounts using the verified token
      const accResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'GET',
        headers: { 
          'auth-token': token,
          'Accept': 'application/json'
        }
      });

      if (accResponse.ok) {
        const data = await accResponse.json();
        const rawAccounts = Array.isArray(data) ? data : (data.accounts || []);

        const enhancedAccounts = await Promise.all(rawAccounts.map(async (acc: any) => {
          let balance = acc.balance || 0;
          let equity = acc.equity || 0;

          if (acc.state === 'DEPLOYED' && acc.connectionStatus === 'CONNECTED') {
            try {
              // Targeted fetch for the specific London Client API node
              const statsRes = await fetch(`https://mt-client-api-abwhvwsgd5ewft1t.london.agiliumtrade.ai/users/current/accounts/${acc._id || acc.id}/account-information`, {
                headers: { 'auth-token': token }
              });
              if (statsRes.ok) {
                const stats = await statsRes.json();
                balance = stats.balance;
                equity = stats.equity;
              }
            } catch (e) {
              // Cluster sync latency - non-critical
            }
          }

          return {
            id: acc._id || acc.id,
            name: acc.name,
            platform: acc.platform === 'mt5' ? PlatformType.MT5 : PlatformType.MT4,
            login: acc.login,
            connectionStatus: acc.connectionStatus || 'DISCONNECTED',
            state: acc.state || 'UNDEPLOYED',
            balance: balance,
            equity: equity
          };
        }));

        setAccounts(enhancedAccounts);
      }
    } catch (err) {
      console.error('Terminal Network Error:', err);
    } finally {
      setIsLoading(false);
    }
  }, [getRawToken]);

  useEffect(() => {
    verifyAndFetch();
    const interval = setInterval(verifyAndFetch, 30000); 
    return () => clearInterval(interval);
  }, [verifyAndFetch]);

  return (
    <div className="flex h-screen bg-[#02040a] overflow-hidden text-slate-200">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-20 border-b border-white/5 flex items-center justify-between px-10 bg-slate-900/10 backdrop-blur-3xl shrink-0 z-20">
          <div className="flex items-center gap-4">
            <Cloud className="w-6 h-6 text-indigo-500 animate-pulse" />
            <h1 className="text-xl font-black text-white tracking-tighter uppercase">
              {activeTab} <span className="text-indigo-500">.london</span>
            </h1>
          </div>

          <div className="flex items-center gap-5">
            {isAuthValid === true ? (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Auth: Active</span>
              </div>
            ) : isAuthValid === false ? (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-rose-500/10 border border-rose-500/20 rounded-xl animate-pulse">
                <AlertCircle className="w-4 h-4 text-rose-500" />
                <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Header Rejected</span>
              </div>
            ) : (
              <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-500/10 border border-slate-500/20 rounded-xl">
                <Loader2 className="w-4 h-4 text-slate-500 animate-spin" />
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Checking...</span>
              </div>
            )}

            <div className="hidden md:flex items-center gap-3 bg-slate-950/50 px-4 py-1.5 rounded-xl text-[10px] font-black text-slate-400 uppercase tracking-widest border border-white/5">
              <div className={`w-2 h-2 rounded-full ${isAuthValid ? 'bg-emerald-500' : 'bg-rose-500 animate-pulse'}`}></div>
              MetaApi: Cluster.London
            </div>

            <button onClick={verifyAndFetch} className="p-2.5 hover:bg-white/5 rounded-xl transition-all">
              <RefreshCw className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} />
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar z-10">
          {activeTab === 'dashboard' && <Dashboard accounts={accounts} isLoading={isLoading} />}
          {activeTab === 'accounts' && <AccountConfig accounts={accounts} setAccounts={setAccounts} />}
          {activeTab === 'risk' && <RiskPanel />}
          {activeTab === 'automation' && <CopyFactoryConfig accounts={accounts} />}
          {activeTab === 'logs' && (
             <div className="p-10 bg-slate-900/40 rounded-[40px] border border-white/5 font-mono text-xs text-slate-500 space-y-2">
               <p className="text-indigo-500 font-black uppercase tracking-widest">[Cluster Diagnosis]</p>
               <p>Target Cluster: london.agiliumtrade.ai</p>
               <p>Auth Method: Static 'auth-token' header</p>
               <p>Token Check: {getRawToken() ? 'Detected (Length: ' + getRawToken().length + ')' : 'MISSING'}</p>
               <p className={`mt-4 ${isAuthValid ? 'text-emerald-500' : 'text-rose-500'}`}>
                 Connection State: {isAuthValid ? 'Handshake Successful' : 'Awaiting Valid Header Validation'}
               </p>
             </div>
          )}
        </div>

        <footer className="h-10 bg-black border-t border-white/5 flex items-center px-10 gap-8 text-[8px] uppercase tracking-[0.4em] font-black text-slate-600 shrink-0 z-20">
          <div className="flex items-center gap-2">
            <Lock className="w-3 h-3 text-indigo-500" />
            EA STATUS: ACTIVE
          </div>
          <div className="ml-auto flex items-center gap-4">
             <span>REGION: london</span>
             <span className="text-indigo-500/50 tracking-normal">auth-token verification enabled</span>
          </div>
        </footer>
      </main>
    </div>
  );
};

