        if (buy > sell) open_buy_trade();
        else if (sell > buy) open_sell_trade();
    }
}

int OnInit() { return INIT_SUCCEEDED; }
void OnTick() { execute_trades(); }
`;

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({ name: '', platform: 'mt4', login: '', password: '', server: '' });

  const getHeaders = () => {
    // RAW extraction: no regex replace to avoid corrupting RSA signature parts
    const token = (process.env.API_KEY || '').trim();
    return {
      'auth-token': token, 
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    };
  };

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Validation: MT4 Login, Master Password, and Server required.");
      return;
    }

    setIsSubmitting(true);
    try {
      const response = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: 'mt4',
          magic: 010101,
          region: 'london',
          expertAdvisor: {
            name: 'TRISPIN-ICT-SCALPER',
            code: TRISPIN_EA_CODE,
            autoStart: true
          }
        })
      });

      const data = await response.json();
      if (!response.ok) throw new Error(data.message || "Auth header rejected by gateway.");

      setAccounts(prev => [...prev, {
        id: data.id || data._id,
        name: data.name,
        platform: PlatformType.MT4,
        login: data.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      alert('Node Provisioned successfully.');
    } catch (err: any) {
      alert(`Provisioning Error: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeployAccount = async (accountId: string) => {
    try {
      const response = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${accountId}/deploy`, {
        method: 'POST',
        headers: getHeaders()
      });
      if (!response.ok) throw new Error("Deployment refused. Check auth-token format.");
      alert("Deployment Initialized.");
      setAccounts(prev => prev.map(acc => acc.id === accountId ? { ...acc, state: 'DEPLOYING' } : acc));
    } catch (err: any) {
      alert(err.message);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md">
        <div className="flex items-center gap-6">
          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Server className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Terminal</h2>
            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Gateway: london.agiliumtrade.ai</p>
          </div>
        </div>
        {!isAdding && (
          <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all">
            + Provision New Node
          </button>
        )}
      </div>

      {isAdding && (
        <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-xl mx-auto shadow-2xl relative overflow-hidden">
          <div className="space-y-6 relative z-10">
            <div className="bg-indigo-500/10 p-4 rounded-xl border border-indigo-500/20 flex items-center gap-3">
              <Zap className="text-indigo-400 w-4 h-4" />
              <span className="text-[10px] font-bold text-indigo-200 uppercase tracking-widest">Auto-Inject: TRISPIN-ICT-SCALPER</span>
            </div>
            <input type="text" placeholder="Terminal Label" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-indigo-500 outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
            <div className="grid grid-cols-2 gap-4">
              <input type="text" placeholder="MT4 Login" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-indigo-500 outline-none" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
              <input type="text" placeholder="Broker Server" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-indigo-500 outline-none" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
            </div>
            <input type="password" placeholder="Master Password" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white focus:border-indigo-500 outline-none" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
            <div className="flex gap-4 pt-4">
              <button onClick={() => setIsAdding(false)} className="flex-1 py-3 text-slate-500 font-bold uppercase tracking-widest">Cancel</button>
              <button onClick={handleCreateAccount} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black transition-all">
                {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : 'Confirm Provisioning'}
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {accounts.map(acc => (
          <div key={acc.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] backdrop-blur-sm group hover:border-indigo-500/30 transition-all shadow-xl">
