          </div>
          <div className="ml-auto flex items-center gap-4">
             <span>REGION: london</span>
             <span className="text-indigo-500/50">Header: auth-token v1</span>
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal, Loader2 } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const getRawToken = () => {
    return (process.env.API_KEY || '').trim();
  };

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) return;

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London cluster copy engine sync...`);

    const TOKEN = getRawToken();
    const COPYFACTORY_BASE = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    const getHeaders = () => ({
      'auth-token': TOKEN,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    });

    try {
      addLog(`Validating Master Access...`);
      const provRes = await fetch(`https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts/${providerId}`, {
        headers: getHeaders()
      });

      if (!provRes.ok) throw new Error(`Gateway Error: Provisioning rejected auth-token.`);

      addLog(`Generating Strategy Node...`);
      const strategyIdRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: getHeaders()
      });

      const strategyData = await strategyIdRes.json();
      const sid = strategyData.id || strategyData._id;

      await fetch(`${COPYFACTORY_BASE}/users/current/configuration/strategies/${sid}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ name: `CF-Sync-${providerId.slice(-4)}`, accountId: providerId })
      });

      addLog(`Attaching Subscriber...`);
      const subRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ 
          name: `Sub-${subscriberId.slice(-4)}`,
          subscriptions: [{ strategyId: sid, multiplier: 1 }] 
        })
      });

      if (!subRes.ok) throw new Error("CopyFactory rejected subscriber attachment.");

      setStatus('success');
      addLog(`SUCCESS: Sync active on London Cluster.`);
    } catch (err: any) {
      setStatus('error');
      addLog(`FATAL: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900/40 border border-white/5 rounded-[40px] p-10 shadow-2xl backdrop-blur-md">
        <div className="flex items-center gap-5 mb-10">
          <div className="w-14 h-14 bg-indigo-600/10 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Layers className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Copy Engine</h2>
            <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mt-1">Gateway: copyfactory.london</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center mb-10 bg-slate-950/50 p-8 rounded-[32px] border border-white/5">
          <div>
            <label className="block text-[9px] font-black text-slate-500 uppercase mb-3 tracking-widest">Master Provider</label>
            <select value={providerId} onChange={(e) => setProviderId(e.target.value)} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-4 text-white outline-none focus:border-indigo-500">
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
          <div className="flex justify-center pt-6"><ArrowRight className="text-indigo-400 w-6 h-6 animate-pulse" /></div>
          <div>
            <label className="block text-[9px] font-black text-slate-500 uppercase mb-3 tracking-widest">Subscriber Node</label>
            <select value={subscriberId} onChange={(e) => setSubscriberId(e.target.value)} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-4 text-white outline-none focus:border-indigo-500">
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <button 
          onClick={handleConfigure} 
          disabled={status === 'configuring' || accounts.length < 2} 
          className="w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-4 bg-indigo-600 hover:bg-indigo-500 text-white transition-all disabled:opacity-50"
        >
          {status === 'configuring' ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
          Enable London Sync
        </button>
      </div>

      <div className="bg-slate-900/40 border border-white/5 rounded-[32px] p-8 h-64 overflow-y-auto font-mono text-[11px] text-slate-400 custom-scrollbar shadow-inner backdrop-blur-sm">
        <div className="text-indigo-500/50 mb-3 font-black tracking-widest uppercase">-- ENGINE_LOG::REGION_LONDON --</div>
        {log.map((line, i) => <div key={i} className="mb-1 border-l-2 border-indigo-500/20 pl-3 py-0.5">{line}</div>)}
      </div>
    </div>
  );
};

