        method: 'GET',
        headers: { 
          'auth-token': token,
          'Accept': 'application/json',
          'Cache-Control': 'no-cache'
        }
      });

      if (!accResponse.ok) {
        setIsAuthValid(false);
        const errText = await accResponse.text();
        console.error(`Auth Failed (${accResponse.status}):`, errText);
        // Log basic info for debugging without leaking the full token
        console.debug("Token Length:", token.length);
        console.debug("Token Start:", token.substring(0, 10));
        return;
      }

      setIsAuthValid(true);
      const data = await accResponse.json();
      const accountsList = Array.isArray(data) ? data : (data.accounts || []);

      const enhancedAccounts = await Promise.all(accountsList.map(async (acc: any) => {
        let balance = acc.balance || 0;
        let equity = acc.equity || 0;

        // Sync live data from London Cluster for active nodes
