               <div>
                 <p className="text-indigo-500 font-black uppercase tracking-widest mb-1">[London Cluster Monitor]</p>
                 <p className="opacity-50">Tracing Agiliumtrade Gateway Protocol...</p>
               </div>
               <div className="space-y-1">
                 <p>API Endpoint: mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai</p>
                 <p>Header: auth-token (Verified)</p>
                 <p>Token Size: {getRawToken().length} bytes</p>
                 <p>Token Checksum: {getRawToken().substring(0, 8)}...{getRawToken().slice(-8)}</p>
               </div>
               <p className={`mt-4 font-black ${isAuthValid ? 'text-emerald-500' : 'text-rose-500'}`}>
                 Connection State: {isAuthValid ? 'HANDSHAKE_COMPLETED_SUCCESS' : 'WAITING_FOR_VALID_AUTH_TOKEN'}
               </p>
             </div>
          )}
        </div>

        <footer className="h-10 bg-black border-t border-white/5 flex items-center px-10 gap-8 text-[8px] uppercase tracking-[0.4em] font-black text-slate-600 shrink-0 z-20">
