import React, { useState, useCallback } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { Plus, Trash2, Server, Globe, Shield, Terminal, Zap, Loader2, Code, Info } from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', // 4 or 5
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET', // Default for many brokers
    dstTimezone: 'EET'
  });

  /**
   * CRITICAL: RAW AUTH HEADER FACTORY
   * This ensures the JWT is never mangled by regex or encoding.
   */
  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    // Specific cleanup for environment variable wrapping
    const cleanToken = raw.replace(/^['"]|['"]$/g, '');
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    };
  }, []);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Required: MT4/5 Login, Master Password, and Server.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();

    try {
      // STEP 1: Create or Get a Provisioning Profile
      // For simplicity, we create a profile named after the server to ensure compatibility
      const profileName = `Profile-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}`;

      const profileRes = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/provisioning-profiles', {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({
          name: profileName,
          version: parseInt(formData.platform),
          brokerTimezone: formData.timezone,
          brokerDSTSwitchTimezone: formData.dstTimezone
        })
      });

      let profileId: string;
      if (profileRes.status === 201) {
        const profileData = await profileRes.json();
        profileId = profileData.id;
      } else {
        // If 400, profile might already exist. We try to find it.
        const listRes = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/provisioning-profiles', {
          headers: headers
        });
        const profiles = await listRes.json();
        const existing = profiles.find((p: any) => p.name === profileName);
        if (!existing) throw new Error("Could not create or locate provisioning profile.");
        profileId = existing.id;
      }

      // STEP 2: Create the actual Trading Account using the Profile ID
      const accountResponse = await fetch('https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai/users/current/accounts', {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({
          name: formData.name || `Terminal-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform === '5' ? 'mt5' : 'mt4',
          provisioningProfileId: profileId,
          magic: 10101,
          region: 'london'
        })
      });

      if (!accountResponse.ok) {
        const errData = await accountResponse.json();
        throw new Error(errData.message || "Failed to link trading account.");
      }

      const newAccount = await accountResponse.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: newAccount.name,
        platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      alert('Node Provisioned successfully in London Cluster.');
    } catch (err: any) {
      console.error("Provisioning Error Details:", err);
      alert(`Provisioning Failed: ${err.message}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md gap-4">
