          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20">
            <Server className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Node Management</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Cluster: London-V1-Provisioning</p>
            </div>
          </div>
        </div>
        {!isAdding && (
          <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all shadow-lg shadow-indigo-600/20 active:scale-95">
            + Provision New Node
          </button>
        )}
      </div>

      {isAdding && (
        <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-2xl mx-auto shadow-2xl relative overflow-hidden animate-in zoom-in-95 duration-300">
          <div className="space-y-6 relative z-10">
            <div className="bg-indigo-500/10 p-4 rounded-xl border border-indigo-500/20 flex items-center gap-3">
              <Info className="text-indigo-400 w-4 h-4" />
              <span className="text-[9px] font-bold text-indigo-200 uppercase tracking-widest leading-none">
                This will create a Provisioning Profile and link your account to the London Cluster.
              </span>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Platform</label>
