  const [step, setStep] = useState<'idle' | 'profile' | 'account'>('idle');
  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', // string "4" or "5"
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  /**
   * CRITICAL AUTH HANDLER
   * Ensures the RAW JWT is transmitted without quote corruption.
   */
  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    // Remove any wrapping quotes that might be injected by the build system
    const cleanToken = raw.replace(/^['"]|['"]$/g, '');
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    };
  }, []);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Please fill in MT Login, Password, and Server address.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

    try {
      // STEP 1: Provisioning Profile Management
      setStep('profile');
      const profileName = `TRISPIN-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      // Try to create the profile
      const profileCreateRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({
          name: profileName,
          version: parseInt(formData.platform),
          brokerTimezone: formData.timezone,
          brokerDSTSwitchTimezone: formData.dstTimezone,
          type: 'mtTerminal'
        })
      });

      let profileId: string = '';

      if (profileCreateRes.status === 201) {
        const data = await profileCreateRes.json();
        profileId = data.id || data._id;
      } else {
        // If it failed (likely because it exists), fetch existing profiles
        const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, {
          headers: headers
        });

        if (!listRes.ok) throw new Error("Authentication failed during profile check (401).");

        const profiles = await listRes.json();
        const existing = profiles.find((p: any) => p.name === profileName);

        if (existing) {
          profileId = existing._id || existing.id;
        } else {
          const errData = await profileCreateRes.json();
          throw new Error(errData.message || "Failed to create provisioning profile.");
        }
      }

      // STEP 2: Account Linking
      setStep('account');
      const accountResponse = await fetch(`${API_BASE}/users/current/accounts`, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify({
          name: formData.name || `Node-${formData.login}`,
          type: 'cloud',
          login: formData.login,
          password: formData.password,
          server: formData.server,
          platform: formData.platform === '5' ? 'mt5' : 'mt4',
          provisioningProfileId: profileId,
          magic: 777,
          region: 'london'
        })
      });

      if (!accountResponse.ok) {
        const accErr = await accountResponse.json();
        throw new Error(accErr.message || "Failed to link trading account to profile.");
      }

      const newAccount = await accountResponse.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: newAccount.name,
        platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
        login: newAccount.login,
        connectionStatus: 'DISCONNECTED',
        state: 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setStep('idle');
      alert('Node provisioning initiated in London.');

    } catch (err: any) {
      console.error("Critical Provisioning Failure:", err);
      alert(err.message);
