  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', // string "4" or "5"
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  /**
   * CLEAN TOKEN HANDLER
   * Strictly sanitizes the JWT to ensure RSA signature remains valid.
   */
  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw
      .replace(/^['"]|['"]$/g, '') // Remove wrapping quotes
      .replace(/bearer/gi, '')     // Remove accidental prefix
      .trim();

    return {
      'auth-token': cleanToken,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    };
  }, []);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Missing connection parameters. Login, Password, and Server are required.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();

    try {
      // PHASE 1: Resolve Provisioning Profile
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      // Step A: Search for existing profile
      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, {
        headers: headers
      });

      if (!listRes.ok) throw new Error("Authentication failed (401). Check if your API Key is valid and active.");

      const profiles = await listRes.json();
      let profileId = profiles.find((p: any) => p.name === profileName)?._id || profiles.find((p: any) => p.name === profileName)?.id;

