export default AccountConfig;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { 
  Trash2, Server, Zap, Loader2, Info, ShieldCheck, 
  Upload, FileCheck, AlertTriangle, Settings2, Database,
  ChevronRight, Pencil, X, Globe
} from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

interface ProvisioningProfile {
  _id?: string;
  id?: string;
  name: string;
  version: number;
  status: string;
  brokerTimezone: string;
  brokerDSTSwitchTimezone: string;
  type: string;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [view, setView] = useState<'accounts' | 'profiles'>('accounts');
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [profiles, setProfiles] = useState<ProvisioningProfile[]>([]);
  const [activeStep, setActiveStep] = useState<'idle' | 'profile-check' | 'profile-create' | 'upload-file' | 'account-link'>('idle');
  const [editingProfile, setEditingProfile] = useState<ProvisioningProfile | null>(null);

  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', 
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const [pendingProfileId, setPendingProfileId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json'
    };
  }, []);

  const fetchProfiles = useCallback(async () => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (res.ok) {
        const data = await res.json();
        setProfiles(data);
      }
    } catch (err) {
      console.error("Failed to fetch profiles:", err);
    }
  }, [getAuthHeader]);

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Required: Login, Password, and Server.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();

    try {
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (!listRes.ok) throw new Error("401: Gateway access denied.");

      const existingProfiles = await listRes.json();
      let profileId = existingProfiles.find((p: any) => p.name === profileName)?._id || existingProfiles.find((p: any) => p.name === profileName)?.id;

      if (!profileId) {
        setActiveStep('profile-create');
        const createRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
          method: 'POST',
          headers: { ...headers, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: profileName,
            version: parseInt(formData.platform),
            brokerTimezone: formData.timezone,
            brokerDSTSwitchTimezone: formData.dstTimezone,
            type: 'mtTerminal'
          })
        });

        if (!createRes.ok) throw new Error("Failed to initialize profile.");
        const newProfile = await createRes.json();
        profileId = newProfile.id || newProfile._id;

        setPendingProfileId(profileId);
        setActiveStep('upload-file');
        setIsSubmitting(false);
        return;
      }

      await completeAccountLink(profileId);
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const targetId = pendingProfileId || editingProfile?.id || editingProfile?._id;
    if (!file || !targetId) return;

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const expectedName = formData.platform === '5' ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');

    const body = new FormData();
    body.append('file', file);

    try {
      const uploadRes = await fetch(`${API_BASE}/users/current/provisioning-profiles/${targetId}/${expectedName}`, {
        method: 'PUT',
        headers: { 'auth-token': headers['auth-token'] },
        body: body
      });

      if (!uploadRes.ok) throw new Error("File upload failed.");

      if (pendingProfileId) {
        await completeAccountLink(pendingProfileId);
      } else {
        alert("File updated successfully.");
        fetchProfiles();
        setEditingProfile(null);
        setIsSubmitting(false);
      }
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
    }
  };

  const handleUpdateProfile = async () => {
    if (!editingProfile) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingProfile.id || editingProfile._id;

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: editingProfile.name,
          brokerTimezone: editingProfile.brokerTimezone,
          brokerDSTSwitchTimezone: editingProfile.brokerDSTSwitchTimezone
        })
      });

      if (!res.ok) throw new Error("Update failed.");

      alert("Profile updated.");
      fetchProfiles();
      setEditingProfile(null);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteProfile = async (id: string) => {
    if (!confirm("Are you sure? This will invalidate all nodes using this profile.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.ok) {
        fetchProfiles();
      }
    } catch (err) {
      alert("Delete failed.");
    }
  };

  const completeAccountLink = async (profileId: string) => {
    setActiveStep('account-link');
    setIsSubmitting(true);
    const headers = getAuthHeader();

    const accountResponse = await fetch(`${API_BASE}/users/current/accounts`, {
      method: 'POST',
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: formData.name || `Node-${formData.login}`,
        type: 'cloud',
        login: formData.login,
        password: formData.password,
        server: formData.server,
        platform: formData.platform === '5' ? 'mt5' : 'mt4',
        provisioningProfileId: profileId,
        magic: 10101,
        region: 'london'
      })
    });

    if (!accountResponse.ok) throw new Error("Linking failed.");

    const newAccount = await accountResponse.json();
    setAccounts(prev => [...prev, {
      id: newAccount.id || newAccount._id,
      name: newAccount.name,
      platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
      login: newAccount.login,
      connectionStatus: 'DISCONNECTED',
      state: 'UNDEPLOYED',
      balance: 0,
      equity: 0
    }]);

    setIsAdding(false);
    setActiveStep('idle');
    setPendingProfileId(null);
    setIsSubmitting(false);
    fetchProfiles();
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md gap-4">
        <div className="flex items-center gap-6">
          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Database className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Hub</h2>
            <div className="flex items-center gap-4 mt-1">
              <button 
                onClick={() => setView('accounts')}
                className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'accounts' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Nodes Cluster
              </button>
              <span className="w-1 h-1 rounded-full bg-slate-800"></span>
              <button 
                onClick={() => { setView('profiles'); fetchProfiles(); }}
                className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'profiles' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Infrastructure Profiles
              </button>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
           {!isAdding && view === 'accounts' && (
             <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all shadow-lg shadow-indigo-600/20 active:scale-95 text-xs uppercase tracking-widest">
               + Provision New Node
             </button>
           )}
        </div>
      </div>

      {view === 'accounts' ? (
        <>
          {isAdding && (
            <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-2xl mx-auto shadow-2xl relative animate-in fade-in zoom-in-95 duration-300">
              <div className="space-y-6 relative z-10">
                <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-4 h-4 text-indigo-400" />
                    <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Secure Node Handshake</span>
                  </div>
                  {isSubmitting && (
                    <div className="flex items-center gap-2 px-4 py-1.5 bg-indigo-500/10 rounded-full border border-indigo-500/20">
                      <Loader2 className="w-3 h-3 text-indigo-400 animate-spin" />
                      <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest">{activeStep}</span>
                    </div>
                  )}
                </div>

                {activeStep === 'upload-file' ? (
                  <div className="space-y-6 text-center py-6 animate-in slide-in-from-right-4 duration-300">
                    <div className="w-20 h-20 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto border border-amber-500/20 mb-4">
                      <Upload className="w-8 h-8 text-amber-500" />
                    </div>
                    <div>
                      <h3 className="text-lg font-black text-white mb-2 tracking-tight">Profile Setup Incomplete</h3>
                      <p className="text-sm text-slate-400 max-w-md mx-auto">
                        New MT{formData.platform} profiles require a server configuration file.
                        <span className="text-indigo-400 font-bold mt-2 block">
                          {formData.platform === '5' ? 'Requires: servers.dat' : 'Requires: *.srv or servers.ini'}
                        </span>
                      </p>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".dat,.ini,.srv" />
                    <div className="flex gap-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Cancel</button>
                      <button onClick={() => fileInputRef.current?.click()} className="flex-[2] bg-amber-600 hover:bg-amber-500 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-3 shadow-lg shadow-amber-600/30">
                        Select File
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Platform</label>
                        <select className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-medium" value={formData.platform} onChange={e => setFormData({...formData, platform: e.target.value})}>
                          <option value="4">MetaTrader 4</option>
                          <option value="5">MetaTrader 5</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Node Label</label>
                        <input type="text" placeholder="e.g. Master-Live" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">MT Login</label>
                        <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Broker Server</label>
                        <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Password</label>
                      <input type="password" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                    </div>
                    <div className="flex gap-4 pt-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Cancel</button>
                      <button onClick={handleCreateAccount} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all hover:bg-indigo-500 disabled:opacity-50 flex items-center justify-center gap-3">
                        {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />}
                        Execute Sequence
                      </button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {accounts.map(acc => (
              <div key={acc.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] backdrop-blur-sm group hover:border-indigo-500/30 transition-all shadow-xl">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-indigo-600/10 rounded-xl flex items-center justify-center font-black text-indigo-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner uppercase">
                      {acc.platform}
                    </div>
                    <div>
                      <h4 className="font-black text-white">{acc.name}</h4>
                      <p className="text-[10px] text-slate-500 font-mono tracking-tighter">{acc.login}</p>
                    </div>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest border ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-slate-800 text-slate-500 border-white/5'}`}>
                    {acc.connectionStatus}
                  </div>
                </div>
                <div className="bg-black/20 p-5 rounded-3xl border border-white/5 mb-6 grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">State</p>
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-tighter">{acc.state}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">Equity</p>
                    <p className="text-sm font-black text-white">${acc.balance?.toLocaleString() || '0.00'}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button disabled={acc.state === 'DEPLOYED'} className="flex-1 bg-white/5 hover:bg-indigo-600 text-indigo-400 hover:text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/5 disabled:opacity-50">
                    {acc.state === 'DEPLOYED' ? 'Online' : 'Deploy Node'}
                  </button>
                  <button className="p-4 bg-rose-500/10 text-rose-500 rounded-xl border border-rose-500/20 transition-all hover:bg-rose-500 hover:text-white">
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div className="space-y-6">
          <div className="grid grid-cols-1 gap-4">
            {profiles.length === 0 && (
              <div className="py-20 bg-slate-900/20 border border-dashed border-white/5 rounded-[40px] flex flex-col items-center justify-center text-center">
                <Globe className="w-12 h-12 text-slate-800 mb-4" />
                <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">No Infrastructure Profiles</p>
              </div>
            )}
            {profiles.map(p => (
              <div key={p.id || p._id} className="bg-slate-900/40 border border-white/5 p-6 rounded-[32px] flex items-center justify-between group hover:border-indigo-500/20 transition-all">
                <div className="flex items-center gap-6">
                  <div className="w-12 h-12 bg-slate-950 rounded-2xl flex items-center justify-center border border-white/5 text-slate-500 font-black group-hover:text-indigo-400 transition-colors">
                    MT{p.version}
                  </div>
                  <div>
                    <h4 className="text-sm font-black text-white tracking-tight">{p.name}</h4>
                    <div className="flex items-center gap-3 mt-1 text-[9px] font-black text-slate-500 uppercase tracking-widest">
                      <span>{p.brokerTimezone}</span>
                      <span className="w-1 h-1 rounded-full bg-slate-800"></span>
                      <span className={p.status === 'new' ? 'text-amber-500' : 'text-indigo-400'}>{p.status}</span>
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <button 
                    onClick={() => setEditingProfile(p)}
                    className="p-3 hover:bg-indigo-500/10 text-slate-500 hover:text-indigo-400 rounded-xl transition-all"
                    title="Edit Infrastructure"
                  >
                    <Settings2 className="w-5 h-5" />
                  </button>
                  <button 
                    onClick={() => handleDeleteProfile(p.id || p._id || '')}
                    className="p-3 hover:bg-rose-500/10 text-slate-500 hover:text-rose-500 rounded-xl transition-all"
                    title="Remove Profile"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>

          {editingProfile && (
            <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
              <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-lg w-full shadow-2xl space-y-6 relative overflow-hidden">
                <div className="flex justify-between items-center mb-2">
                  <h3 className="text-lg font-black text-white uppercase tracking-widest">Update Profile</h3>
                  <button onClick={() => setEditingProfile(null)} className="p-2 text-slate-500 hover:text-white transition-colors">
                    <X className="w-6 h-6" />
                  </button>
                </div>

                <div className="space-y-4">
                   <div>
                     <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Profile Name</label>
                     <input 
                       type="text" 
                       className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" 
                       value={editingProfile.name} 
                       onChange={e => setEditingProfile({...editingProfile, name: e.target.value})} 
                     />
                   </div>
                   <div className="grid grid-cols-2 gap-4">
                     <div>
                       <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Timezone</label>
                       <input 
                         type="text" 
                         className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" 
                         value={editingProfile.brokerTimezone} 
                         onChange={e => setEditingProfile({...editingProfile, brokerTimezone: e.target.value})} 
                       />
                     </div>
                     <div>
                       <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">DST Policy</label>
                       <input 
                         type="text" 
                         className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" 
                         value={editingProfile.brokerDSTSwitchTimezone} 
                         onChange={e => setEditingProfile({...editingProfile, brokerDSTSwitchTimezone: e.target.value})} 
                       />
                     </div>
                   </div>

                   <div className="pt-4 space-y-3">
                     <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-2">Sync Server Configuration</p>
                     <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".dat,.ini,.srv" />
                     <button 
                       onClick={() => fileInputRef.current?.click()}
                       className="w-full py-4 bg-white/5 border border-white/5 rounded-xl text-[10px] font-black uppercase text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-3"
                     >
                       <Upload className="w-4 h-4" />
                       Update Server Config File
                     </button>
                   </div>
                </div>

                <div className="flex gap-4 pt-6 border-t border-white/5">
                  <button onClick={() => setEditingProfile(null)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Discard</button>
                  <button 
                    onClick={handleUpdateProfile} 
                    disabled={isSubmitting}
                    className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all hover:bg-indigo-500 disabled:opacity-50 flex items-center justify-center gap-3 shadow-lg shadow-indigo-600/30"
                  >
                    {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <ShieldCheck className="w-4 h-4" />}
                    Save Metadata
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AccountConfig;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { 
  Trash2, Server, Zap, Loader2, Info, ShieldCheck, 
  Upload, FileCheck, AlertTriangle, Settings2, Database,
  ChevronRight, Pencil, X, Globe, Key, RefreshCw
} from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

interface ProvisioningProfile {
  _id?: string;
  id?: string;
  name: string;
  version: number;
  status: string;
  brokerTimezone: string;
  brokerDSTSwitchTimezone: string;
  type: string;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [view, setView] = useState<'accounts' | 'profiles'>('accounts');
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [profiles, setProfiles] = useState<ProvisioningProfile[]>([]);
  const [activeStep, setActiveStep] = useState<'idle' | 'profile-check' | 'profile-create' | 'upload-file' | 'account-link'>('idle');
  const [editingProfile, setEditingProfile] = useState<ProvisioningProfile | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<TradingAccount | null>(null);

  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', 
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const [pendingProfileId, setPendingProfileId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json'
    };
  }, []);

  const fetchProfiles = useCallback(async () => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (res.ok) {
        const data = await res.json();
        setProfiles(data);
      }
    } catch (err) {
      console.error("Failed to fetch profiles:", err);
    }
  }, [getAuthHeader]);

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Required: Login, Password, and Server.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();

    try {
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      const existingProfiles = await listRes.json();
      let profileId = existingProfiles.find((p: any) => p.name === profileName)?._id || existingProfiles.find((p: any) => p.name === profileName)?.id;

      if (!profileId) {
        setActiveStep('profile-create');
        const createRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
          method: 'POST',
          headers: { ...headers, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: profileName,
            version: parseInt(formData.platform),
            brokerTimezone: formData.timezone,
            brokerDSTSwitchTimezone: formData.dstTimezone,
            type: 'mtTerminal'
          })
        });

        if (!createRes.ok) throw new Error("Failed to initialize profile.");
        const newProfile = await createRes.json();
        profileId = newProfile.id || newProfile._id;

        setPendingProfileId(profileId);
        setActiveStep('upload-file');
        setIsSubmitting(false);
        return;
      }

      await completeAccountLink(profileId);
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const handleUpdateCredentials = async () => {
    if (!editingCredentials) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingCredentials.id;

    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}/credentials`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          login: formData.login,
          password: formData.password,
          serverName: formData.server
        })
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.message || "Failed to update credentials.");
      }

      alert("Credentials synchronized with cloud node.");
      setEditingCredentials(null);
      // We don't need to refresh local state as account ID remains same
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteAccount = async (id: string) => {
    if (!confirm("Delete this cloud node? It will stop all trading immediately.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.ok) {
        setAccounts(prev => prev.filter(a => a.id !== id));
      }
    } catch (err) {
      alert("Delete failed.");
    }
  };

  const handleDeleteProfile = async (id: string) => {
    if (!confirm("Remove infrastructure profile? Required: All linked nodes must be deleted first.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.status === 400) {
        alert("Action Denied: One or more accounts are currently linked to this profile. Delete those accounts first.");
        return;
      }
      if (res.ok) {
        fetchProfiles();
      }
    } catch (err) {
      alert("Delete failed.");
    }
  };

  const completeAccountLink = async (profileId: string) => {
    setActiveStep('account-link');
    setIsSubmitting(true);
    const headers = getAuthHeader();

    const accountResponse = await fetch(`${API_BASE}/users/current/accounts`, {
      method: 'POST',
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: formData.name || `Node-${formData.login}`,
        type: 'cloud',
        login: formData.login,
        password: formData.password,
        server: formData.server,
        platform: formData.platform === '5' ? 'mt5' : 'mt4',
        provisioningProfileId: profileId,
        magic: 10101,
        region: 'london'
      })
    });

    if (!accountResponse.ok) throw new Error("Linking failed.");

    const newAccount = await accountResponse.json();
    setAccounts(prev => [...prev, {
      id: newAccount.id || newAccount._id,
      name: newAccount.name,
      platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
      login: newAccount.login,
      connectionStatus: 'DISCONNECTED',
      state: 'UNDEPLOYED',
      balance: 0,
      equity: 0
    }]);

    setIsAdding(false);
    setActiveStep('idle');
    setPendingProfileId(null);
    setIsSubmitting(false);
    fetchProfiles();
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md gap-4">
        <div className="flex items-center gap-6">
          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Database className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Hub</h2>
            <div className="flex items-center gap-4 mt-1">
              <button onClick={() => setView('accounts')} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'accounts' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Nodes Cluster</button>
              <span className="w-1 h-1 rounded-full bg-slate-800"></span>
              <button onClick={() => { setView('profiles'); fetchProfiles(); }} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'profiles' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Infrastructure</button>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
           {!isAdding && view === 'accounts' && (
             <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all shadow-lg shadow-indigo-600/20 active:scale-95 text-xs uppercase tracking-widest">
               + Provision New Node
             </button>
           )}
        </div>
      </div>

      {view === 'accounts' ? (
        <>
          {isAdding && (
            <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-2xl mx-auto shadow-2xl relative animate-in fade-in zoom-in-95 duration-300">
              <div className="space-y-6 relative z-10">
                <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-4 h-4 text-indigo-400" />
                    <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Secure Node Handshake</span>
                  </div>
                </div>

                {activeStep === 'upload-file' ? (
                  <div className="space-y-6 text-center py-6 animate-in slide-in-from-right-4 duration-300">
                    <div className="w-20 h-20 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto border border-amber-500/20 mb-4">
                      <Upload className="w-8 h-8 text-amber-500" />
                    </div>
                    <div>
                      <h3 className="text-lg font-black text-white mb-2 tracking-tight">Profile Setup Incomplete</h3>
                      <p className="text-sm text-slate-400 max-w-md mx-auto">Upload server configuration for MT{formData.platform}.</p>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={(e) => {
                       const file = e.target.files?.[0];
                       if (!file || !pendingProfileId) return;
                       setIsSubmitting(true);
                       const headers = getAuthHeader();
                       const expectedName = formData.platform === '5' ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');
                       const body = new FormData();
                       body.append('file', file);
                       fetch(`${API_BASE}/users/current/provisioning-profiles/${pendingProfileId}/${expectedName}`, {
                         method: 'PUT',
                         headers: { 'auth-token': headers['auth-token'] },
                         body: body
                       }).then(res => res.ok ? completeAccountLink(pendingProfileId) : alert("Upload failed.")).catch(() => alert("Error during upload."));
                    }} className="hidden" accept=".dat,.ini,.srv" />
                    <div className="flex gap-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Cancel</button>
                      <button onClick={() => fileInputRef.current?.click()} className="flex-[2] bg-amber-600 hover:bg-amber-500 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-3">
                        <FileCheck className="w-4 h-4" /> Select File
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Platform</label>
                        <select className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-medium" value={formData.platform} onChange={e => setFormData({...formData, platform: e.target.value})}>
                          <option value="4">MetaTrader 4</option>
                          <option value="5">MetaTrader 5</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Label</label>
                        <input type="text" placeholder="e.g. Master-Live" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">MT Login</label>
                        <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Server</label>
                        <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Password</label>
                      <input type="password" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                    </div>
                    <div className="flex gap-4 pt-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Cancel</button>
                      <button onClick={handleCreateAccount} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all hover:bg-indigo-500 disabled:opacity-50 flex items-center justify-center gap-3">
                        {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Zap className="w-4 h-4" />} Execute
                      </button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {accounts.map(acc => (
              <div key={acc.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] backdrop-blur-sm group hover:border-indigo-500/30 transition-all shadow-xl">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-indigo-600/10 rounded-xl flex items-center justify-center font-black text-indigo-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner uppercase">{acc.platform}</div>
                    <div>
                      <h4 className="font-black text-white">{acc.name}</h4>
                      <p className="text-[10px] text-slate-500 font-mono tracking-tighter">{acc.login}</p>
                    </div>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest border ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-slate-800 text-slate-500 border-white/5'}`}>{acc.connectionStatus}</div>
                </div>
                <div className="bg-black/20 p-5 rounded-3xl border border-white/5 mb-6 grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">State</p>
                    <p className="text-xs font-black text-indigo-400 uppercase tracking-tighter">{acc.state}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">Equity</p>
                    <p className="text-sm font-black text-white">${acc.balance?.toLocaleString() || '0.00'}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => { setEditingCredentials(acc); setFormData({...formData, login: acc.login, server: ''}); }} className="p-4 bg-white/5 text-slate-400 hover:text-white rounded-xl border border-white/5 transition-all"><Key className="w-4 h-4" /></button>
                  <button disabled={acc.state === 'DEPLOYED'} className="flex-1 bg-white/5 hover:bg-indigo-600 text-indigo-400 hover:text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/5 disabled:opacity-50">{acc.state === 'DEPLOYED' ? 'Online' : 'Deploy'}</button>
                  <button onClick={() => handleDeleteAccount(acc.id)} className="p-4 bg-rose-500/10 text-rose-500 rounded-xl border border-rose-500/20 transition-all hover:bg-rose-500 hover:text-white"><Trash2 className="w-4 h-4" /></button>
                </div>
              </div>
            ))}
          </div>

          {editingCredentials && (
            <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
               <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-lg w-full shadow-2xl space-y-6">
                 <div className="flex justify-between items-center border-b border-white/5 pb-6">
                    <div className="flex items-center gap-3">
                      <Key className="w-5 h-5 text-indigo-400" />
                      <h3 className="text-lg font-black text-white uppercase tracking-widest">Update Credentials</h3>
                    </div>
                    <button onClick={() => setEditingCredentials(null)} className="text-slate-500 hover:text-white"><X /></button>
                 </div>
                 <div className="space-y-4">
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">MT Login</label>
                     <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-mono" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">New Password</label>
                     <input type="password" placeholder="••••••••" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">Server Name</label>
                     <input type="text" placeholder="e.g. IC-Markets-Live-2" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-mono" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
                   </div>
                 </div>
                 <div className="flex gap-4 pt-6 border-t border-white/5">
                   <button onClick={() => setEditingCredentials(null)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px]">Discard</button>
                   <button onClick={handleUpdateCredentials} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-600/30 flex items-center justify-center gap-3">
                     {isSubmitting ? <Loader2 className="animate-spin w-4 h-4" /> : <RefreshCw className="w-4 h-4" />} Hot-Sync Credentials
                   </button>
                 </div>
               </div>
            </div>
          )}
        </>
      ) : (
        <div className="space-y-6">
          <div className="grid grid-cols-1 gap-4">
            {profiles.length === 0 && (
              <div className="py-20 bg-slate-900/20 border border-dashed border-white/5 rounded-[40px] flex flex-col items-center justify-center text-center">
                <Globe className="w-12 h-12 text-slate-800 mb-4" />
                <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">No Infrastructure Profiles Found</p>
              </div>
            )}
            {profiles.map(p => (
              <div key={p.id || p._id} className="bg-slate-900/40 border border-white/5 p-6 rounded-[32px] flex items-center justify-between group hover:border-indigo-500/20 transition-all">
                <div className="flex items-center gap-6">
                  <div className="w-12 h-12 bg-slate-950 rounded-2xl flex items-center justify-center border border-white/5 text-slate-500 font-black group-hover:text-indigo-400 transition-colors uppercase">MT{p.version}</div>
                  <div>
                    <h4 className="text-sm font-black text-white tracking-tight">{p.name}</h4>
                    <div className="flex items-center gap-3 mt-1 text-[9px] font-black text-slate-500 uppercase tracking-widest">
                      <span>{p.brokerTimezone}</span>
                      <span className="w-1 h-1 rounded-full bg-slate-800"></span>
                      <span className={p.status === 'new' ? 'text-amber-500' : 'text-indigo-400'}>{p.status}</span>
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => setEditingProfile(p)} className="p-3 hover:bg-indigo-500/10 text-slate-500 hover:text-indigo-400 rounded-xl transition-all"><Settings2 className="w-5 h-5" /></button>
                  <button onClick={() => handleDeleteProfile(p.id || p._id || '')} className="p-3 hover:bg-rose-500/10 text-slate-500 hover:text-rose-500 rounded-xl transition-all"><Trash2 className="w-5 h-5" /></button>
                </div>
              </div>
            ))}
          </div>

          {editingProfile && (
            <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
              <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-lg w-full shadow-2xl space-y-6">
                <div className="flex justify-between items-center"><h3 className="text-lg font-black text-white uppercase tracking-widest">Update Infrastructure</h3><button onClick={() => setEditingProfile(null)} className="text-slate-500 hover:text-white"><X /></button></div>
                <div className="space-y-4">
                   <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Profile Name</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.name} onChange={e => setEditingProfile({...editingProfile, name: e.target.value})} /></div>
                   <div className="grid grid-cols-2 gap-4">
                     <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Timezone</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.brokerTimezone} onChange={e => setEditingProfile({...editingProfile, brokerTimezone: e.target.value})} /></div>
                     <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">DST Policy</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.brokerDSTSwitchTimezone} onChange={e => setEditingProfile({...editingProfile, brokerDSTSwitchTimezone: e.target.value})} /></div>
                   </div>
                   <div className="pt-4"><p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-2">Sync Server Config</p>
                     <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".dat,.ini,.srv" />
                     <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-white/5 border border-white/5 rounded-xl text-[10px] font-black uppercase text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-3"><Upload className="w-4 h-4" /> Update Config File</button>
                   </div>
                </div>
                <div className="flex gap-4 pt-6 border-t border-white/5">
                  <button onClick={() => setEditingProfile(null)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px]">Discard</button>
                  <button onClick={handleUpdateProfile} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase transition-all hover:bg-indigo-500 shadow-lg shadow-indigo-600/30 flex items-center justify-center gap-3">
                    {isSubmitting ? <Loader2 className="animate-spin w-4 h-4" /> : <ShieldCheck className="w-4 h-4" />} Save Metadata
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AccountConfig;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { 
  Trash2, Server, Zap, Loader2, Info, ShieldCheck, 
  Upload, FileCheck, AlertTriangle, Settings2, Database,
  ChevronRight, Pencil, X, Globe, Key, RefreshCw
} from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

interface ProvisioningProfile {
  _id?: string;
  id?: string;
  name: string;
  version: number;
  status: string;
  brokerTimezone: string;
  brokerDSTSwitchTimezone: string;
  type: string;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [view, setView] = useState<'accounts' | 'profiles'>('accounts');
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [profiles, setProfiles] = useState<ProvisioningProfile[]>([]);
  const [activeStep, setActiveStep] = useState<'idle' | 'profile-check' | 'profile-create' | 'upload-file' | 'account-link'>('idle');
  const [editingProfile, setEditingProfile] = useState<ProvisioningProfile | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<TradingAccount | null>(null);

  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', 
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const [pendingProfileId, setPendingProfileId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json'
    };
  }, []);

  const fetchProfiles = useCallback(async () => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (res.ok) {
        const data = await res.json();
        setProfiles(data);
      }
    } catch (err) {
      console.error("Failed to fetch profiles:", err);
    }
  }, [getAuthHeader]);

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const handleCreateAccount = async () => {
    if (!formData.login || !formData.password || !formData.server) {
      alert("Required: Login, Password, and Server.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();

    try {
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      const existingProfiles = await listRes.json();
      let profileId = existingProfiles.find((p: any) => p.name === profileName)?._id || existingProfiles.find((p: any) => p.name === profileName)?.id;

      if (!profileId) {
        setActiveStep('profile-create');
        const createRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
          method: 'POST',
          headers: { ...headers, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: profileName,
            version: parseInt(formData.platform),
            brokerTimezone: formData.timezone,
            brokerDSTSwitchTimezone: formData.dstTimezone,
            type: 'mtTerminal'
          })
        });

        if (!createRes.ok) throw new Error("Failed to initialize profile.");
        const newProfile = await createRes.json();
        profileId = newProfile.id || newProfile._id;

        setPendingProfileId(profileId);
        setActiveStep('upload-file');
        setIsSubmitting(false);
        return;
      }

      await completeAccountLink(profileId);
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const handleUpdateCredentials = async () => {
    if (!editingCredentials) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingCredentials.id;

    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}/credentials`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          login: formData.login,
          password: formData.password,
          serverName: formData.server
        })
      });

      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.message || "Failed to update credentials.");
      }

      alert("Credentials synchronized with cloud node.");
      setEditingCredentials(null);
      // We don't need to refresh local state as account ID remains same
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteAccount = async (id: string) => {
    if (!confirm("Delete this cloud node? It will stop all trading immediately.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.ok) {
        setAccounts(prev => prev.filter(a => a.id !== id));
      }
    } catch (err) {
      alert("Delete failed.");
    }
  };

  const handleDeleteProfile = async (id: string) => {
    if (!confirm("Remove infrastructure profile? Required: All linked nodes must be deleted first.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.status === 400) {
        alert("Action Denied: One or more accounts are currently linked to this profile. Delete those accounts first.");
        return;
      }
      if (res.ok) {
        fetchProfiles();
      }
    } catch (err) {
      alert("Delete failed.");
    }
  };

  const completeAccountLink = async (profileId: string) => {
    setActiveStep('account-link');
    setIsSubmitting(true);
    const headers = getAuthHeader();

    const accountResponse = await fetch(`${API_BASE}/users/current/accounts`, {
      method: 'POST',
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        name: formData.name || `Node-${formData.login}`,
        type: 'cloud',
        login: formData.login,
        password: formData.password,
        server: formData.server,
        platform: formData.platform === '5' ? 'mt5' : 'mt4',
        provisioningProfileId: profileId,
        magic: 10101,
        region: 'london'
      })
    });

    if (!accountResponse.ok) throw new Error("Linking failed.");

    const newAccount = await accountResponse.json();
    setAccounts(prev => [...prev, {
      id: newAccount.id || newAccount._id,
      name: newAccount.name,
      platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
      login: newAccount.login,
      connectionStatus: 'DISCONNECTED',
      state: 'UNDEPLOYED',
      balance: 0,
      equity: 0
    }]);

    setIsAdding(false);
    setActiveStep('idle');
    setPendingProfileId(null);
    setIsSubmitting(false);
    fetchProfiles();
  };

  // Fix: Implemented handleFileUpload for infrastructure profile updates
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !editingProfile) return;

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const profileId = editingProfile.id || editingProfile._id;
    const expectedName = editingProfile.version === 5 ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');

    const body = new FormData();
    body.append('file', file);

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${profileId}/${expectedName}`, {
        method: 'PUT',
        headers: { 'auth-token': headers['auth-token'] },
        body: body
      });
      if (!res.ok) throw new Error("Upload failed.");
      alert("Server configuration synchronized.");
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Fix: Implemented handleUpdateProfile for infrastructure metadata changes
  const handleUpdateProfile = async () => {
    if (!editingProfile) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingProfile.id || editingProfile._id;

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: editingProfile.name,
          brokerTimezone: editingProfile.brokerTimezone,
          brokerDSTSwitchTimezone: editingProfile.brokerDSTSwitchTimezone
        })
      });

      if (!res.ok) throw new Error("Failed to update profile metadata.");

      setEditingProfile(null);
      fetchProfiles();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md gap-4">
        <div className="flex items-center gap-6">
          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Database className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Hub</h2>
            <div className="flex items-center gap-4 mt-1">
              <button onClick={() => setView('accounts')} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'accounts' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Nodes Cluster</button>
              <span className="w-1 h-1 rounded-full bg-slate-800"></span>
              <button onClick={() => { setView('profiles'); fetchProfiles(); }} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'profiles' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Infrastructure</button>
            </div>
          </div>
        </div>
        <div className="flex gap-2">
           {!isAdding && view === 'accounts' && (
             <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all shadow-lg shadow-indigo-600/20 active:scale-95 text-xs uppercase tracking-widest">
               + Provision New Node
             </button>
           )}
        </div>
      </div>

      {view === 'accounts' ? (
        <>
          {isAdding && (
            <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-2xl mx-auto shadow-2xl relative animate-in fade-in zoom-in-95 duration-300">
              <div className="space-y-6 relative z-10">
                <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-4 h-4 text-indigo-400" />
                    <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Secure Node Handshake</span>
                  </div>
                </div>

                {activeStep === 'upload-file' ? (
                  <div className="space-y-6 text-center py-6 animate-in slide-in-from-right-4 duration-300">
                    <div className="w-20 h-20 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto border border-amber-500/20 mb-4">
                      <Upload className="w-8 h-8 text-amber-500" />
                    </div>
                    <div>
                      <h3 className="text-lg font-black text-white mb-2 tracking-tight">Profile Setup Incomplete</h3>
                      <p className="text-sm text-slate-400 max-w-md mx-auto">Upload server configuration for MT{formData.platform}.</p>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={(e) => {
                       const file = e.target.files?.[0];
                       if (!file || !pendingProfileId) return;
                       setIsSubmitting(true);
                       const headers = getAuthHeader();
                       const expectedName = formData.platform === '5' ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');
                       const body = new FormData();
                       body.append('file', file);
                       fetch(`${API_BASE}/users/current/provisioning-profiles/${pendingProfileId}/${expectedName}`, {
                         method: 'PUT',
                         headers: { 'auth-token': headers['auth-token'] },
                         body: body
                       }).then(res => res.ok ? completeAccountLink(pendingProfileId) : alert("Upload failed.")).catch(() => alert("Error during upload."));
                    }} className="hidden" accept=".dat,.ini,.srv" />
                    <div className="flex gap-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Cancel</button>
                      <button onClick={() => fileInputRef.current?.click()} className="flex-[2] bg-amber-600 hover:bg-amber-500 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-3">
                        <FileCheck className="w-4 h-4" /> Select File
                      </button>
