export default AccountConfig;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { TradingAccount, PlatformType } from '../types';
import { 
  Trash2, Server, Zap, Loader2, Info, ShieldCheck, 
  Upload, FileCheck, AlertTriangle, Settings2, Database,
  ChevronRight, Pencil, X, Globe, Key, RefreshCw, Power, PowerOff, Link as LinkIcon
} from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

interface ProvisioningProfile {
  _id?: string;
  id?: string;
  name: string;
  version: number;
  status: string;
  brokerTimezone: string;
  brokerDSTSwitchTimezone: string;
  type: string;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [view, setView] = useState<'accounts' | 'profiles'>('accounts');
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [profiles, setProfiles] = useState<ProvisioningProfile[]>([]);
  const [activeStep, setActiveStep] = useState<'idle' | 'profile-check' | 'profile-create' | 'upload-file' | 'account-link' | 'polling'>('idle');
  const [editingProfile, setEditingProfile] = useState<ProvisioningProfile | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<TradingAccount | null>(null);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [pollingMessage, setPollingMessage] = useState<string>('');

  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', 
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const [pendingProfileId, setPendingProfileId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  const generateTransactionId = () => {
    return Array.from({ length: 32 }, () => Math.floor(Math.random() * 16).toString(16)).join('');
  };

  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json'
    };
  }, []);

  const fetchProfiles = useCallback(async () => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (res.ok) {
        const data = await res.json();
        setProfiles(data);
      }
    } catch (err) {
      console.error("Failed to fetch profiles:", err);
    }
  }, [getAuthHeader]);

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const handleNodeAction = async (accountId: string, action: 'deploy' | 'undeploy' | 'redeploy') => {
    setActionLoading(`${accountId}-${action}`);
    const headers = getAuthHeader();
    try {
      const url = action === 'deploy' 
        ? `${API_BASE}/users/current/accounts/${accountId}/deploy?executeForAllReplicas=true`
        : `${API_BASE}/users/current/accounts/${accountId}/${action}`;

      const res = await fetch(url, {
        method: 'POST',
        headers
      });

      if (!res.ok && res.status !== 204) {
        const err = await res.json();
        throw new Error(err.message || `Action ${action} failed.`);
      }

      alert(`Node ${action} sequence initiated successfully.`);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setActionLoading(null);
    }
  };

  const generateConfigLink = async (accountId: string) => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${accountId}/configuration-link?ttlInDays=7`, {
        method: 'PUT',
        headers
      });
      if (res.ok) {
        const data = await res.json();
        const url = data.configurationLink;
        if (confirm(`Secure configuration link generated:\n\n${url}\n\nCopy to clipboard?`)) {
          navigator.clipboard.writeText(url);
        }
      }
    } catch (err) {
      alert("Failed to generate configuration link.");
    }
  };

  const handleCreateAccount = async () => {
    if (!formData.name || !formData.server) {
      alert("Account Name and Server are required for provisioning.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const transactionId = generateTransactionId();

    try {
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      const existingProfiles = await listRes.json();
      let profileId = existingProfiles.find((p: any) => p.name === profileName)?._id || existingProfiles.find((p: any) => p.name === profileName)?.id;

      if (!profileId) {
        setActiveStep('profile-create');
        const createRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
          method: 'POST',
          headers: { ...headers, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: profileName,
            version: parseInt(formData.platform),
            brokerTimezone: formData.timezone,
            brokerDSTSwitchTimezone: formData.dstTimezone,
            type: 'mtTerminal'
          })
        });

        if (!createRes.ok) throw new Error("Failed to initialize cloud infrastructure.");
        const newProfile = await createRes.json();
        profileId = newProfile.id || newProfile._id;

        setPendingProfileId(profileId);
        setActiveStep('upload-file');
        setIsSubmitting(false);
        return;
      }

      await executeProvisioning(profileId, transactionId);
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const executeProvisioning = async (profileId: string, transactionId: string) => {
    setActiveStep('account-link');
    setIsSubmitting(true);
    const headers = getAuthHeader();

    const payload: any = {
      name: formData.name,
      server: formData.server,
      magic: 10101,
      provisioningProfileId: profileId,
      reliability: 'high',
      region: 'london',
      type: 'cloud-g2'
    };

    if (formData.login) payload.login = formData.login;
    if (formData.password) payload.password = formData.password;
    if (!profileId) payload.platform = formData.platform === '5' ? 'mt5' : 'mt4';

    try {
      const response = await fetch(`${API_BASE}/users/current/accounts`, {
        method: 'POST',
        headers: { 
          ...headers, 
          'Content-Type': 'application/json',
          'transaction-id': transactionId
        },
        body: JSON.stringify(payload)
      });

      if (response.status === 202) {
        const data = await response.json();
        setPollingMessage(data.message || "Automatic broker settings detection in progress...");
        setActiveStep('polling');

        // Polling loop with identical transaction ID
        setTimeout(() => executeProvisioning(profileId, transactionId), 30000);
        return;
      }

      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.message || "Onboarding rejected by gateway.");
      }

      const newAccount = await response.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: formData.name,
        platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
        login: formData.login || 'PENDING',
        connectionStatus: 'DISCONNECTED',
        state: newAccount.state || 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setActiveStep('idle');
      setPendingProfileId(null);
      setIsSubmitting(false);
      fetchProfiles();
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const handleUpdateAccountFull = async () => {
    if (!editingCredentials) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingCredentials.id;

    try {
      // Step 1: PUT Update (Metadata & Active Settings)
      const updateRes = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formData.name,
          server: formData.server,
          password: formData.password,
          manualTrades: false,
          magic: 10101
        })
      });

      if (!updateRes.ok && updateRes.status !== 204) {
        const err = await updateRes.json();
        throw new Error(err.message || "Account update rejected.");
      }

      // Step 2: Sync credentials separately for protocol reliability
      await fetch(`${API_BASE}/users/current/accounts/${id}/credentials`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          login: formData.login,
          password: formData.password,
          serverName: formData.server
        })
      });

      alert("Configuration synced. Hardware redeploy required.");
      await handleNodeAction(id, 'redeploy');
      setEditingCredentials(null);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteAccount = async (id: string) => {
    if (!confirm("Remove node from cluster? All cloud resources will be released.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.ok) {
        setAccounts(prev => prev.filter(a => a.id !== id));
      }
    } catch (err) {
      alert("Node deletion failed.");
    }
  };

  const handleDeleteProfile = async (id: string) => {
    if (!confirm("Destroy infrastructure profile? Node dependencies must be zero.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.status === 400) {
        alert("Infrastructure Error: This profile is actively used by trading nodes.");
        return;
      }
      if (res.ok) {
        fetchProfiles();
      }
    } catch (err) {
      alert("Failed to destroy profile.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const targetId = pendingProfileId || (editingProfile?.id || editingProfile?._id);
    if (!file || !targetId) return;

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const version = editingProfile ? editingProfile.version : parseInt(formData.platform);
    const expectedName = version === 5 ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');

    const body = new FormData();
    body.append('file', file);

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${targetId}/${expectedName}`, {
        method: 'PUT',
        headers: { 'auth-token': headers['auth-token'] },
        body: body
      });
      if (!res.ok) throw new Error("Terminal file synchronization failed.");

      if (pendingProfileId) {
        const transactionId = generateTransactionId();
        await executeProvisioning(pendingProfileId, transactionId);
      } else {
        alert("Cloud configuration updated.");
        fetchProfiles();
      }
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleUpdateProfile = async () => {
    if (!editingProfile) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingProfile.id || editingProfile._id;

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: editingProfile.name,
          brokerTimezone: editingProfile.brokerTimezone,
          brokerDSTSwitchTimezone: editingProfile.brokerDSTSwitchTimezone
        })
      });

      if (!res.ok) throw new Error("Metadata update rejected.");

      setEditingProfile(null);
      fetchProfiles();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const getUsageCount = (profileId: string) => {
    return accounts.filter(a => (a as any).provisioningProfileId === profileId).length;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white/5 p-8 rounded-[40px] border border-white/5 backdrop-blur-md gap-4">
        <div className="flex items-center gap-6">
          <div className="w-14 h-14 bg-indigo-500/10 rounded-2xl flex items-center justify-center border border-indigo-500/20 shadow-inner">
            <Database className="text-indigo-400 w-7 h-7" />
          </div>
          <div>
            <h2 className="text-2xl font-black text-white tracking-tight">Provisioning Hub</h2>
            <div className="flex items-center gap-4 mt-1">
              <button onClick={() => setView('accounts')} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'accounts' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Active Cluster</button>
              <span className="w-1 h-1 rounded-full bg-slate-800"></span>
              <button onClick={() => { setView('profiles'); fetchProfiles(); }} className={`text-[10px] font-black uppercase tracking-widest transition-colors ${view === 'profiles' ? 'text-indigo-400' : 'text-slate-500 hover:text-slate-300'}`}>Terminal Sets</button>
            </div>
          </div>
        </div>
        {!isAdding && view === 'accounts' && (
          <button onClick={() => setIsAdding(true)} className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-xl font-black transition-all shadow-lg shadow-indigo-600/20 active:scale-95 text-xs uppercase tracking-widest">
            + Provision Node
          </button>
        )}
      </div>

      {view === 'accounts' ? (
        <>
          {isAdding && (
            <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-2xl mx-auto shadow-2xl relative animate-in fade-in zoom-in-95 duration-300">
              <div className="space-y-6 relative z-10">
                <div className="flex justify-between items-center mb-4 border-b border-white/5 pb-4">
                  <div className="flex items-center gap-2">
                    <ShieldCheck className="w-4 h-4 text-indigo-400" />
                    <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Transaction Protocol v2</span>
                  </div>
                  {activeStep === 'polling' && <Loader2 className="w-4 h-4 text-indigo-500 animate-spin" />}
                </div>

                {activeStep === 'upload-file' ? (
                  <div className="space-y-6 text-center py-6">
                    <div className="w-20 h-20 bg-amber-500/10 rounded-full flex items-center justify-center mx-auto border border-amber-500/20 mb-4">
                      <Upload className="w-8 h-8 text-amber-500" />
                    </div>
                    <div>
                      <h3 className="text-lg font-black text-white mb-2">Broker Config Required</h3>
                      <p className="text-sm text-slate-400 max-w-md mx-auto">Please select the MetaTrader server file (.dat/.srv) for this connection.</p>
                    </div>
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".dat,.ini,.srv" />
                    <div className="flex gap-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase text-[10px]">Cancel</button>
                      <button onClick={() => fileInputRef.current?.click()} className="flex-[2] bg-amber-600 hover:bg-amber-500 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all flex items-center justify-center gap-3">
                        <FileCheck className="w-4 h-4" /> Select File
                      </button>
                    </div>
                  </div>
                ) : activeStep === 'polling' ? (
                  <div className="py-12 text-center space-y-6">
                    <div className="w-24 h-24 bg-indigo-500/10 rounded-full flex items-center justify-center mx-auto border-4 border-indigo-500/20 border-t-indigo-500 animate-spin"></div>
                    <div>
                      <h3 className="text-xl font-black text-white uppercase tracking-tighter">Performing Handshake...</h3>
                      <p className="text-slate-400 text-sm mt-2 font-mono">{pollingMessage}</p>
                      <p className="text-[10px] text-slate-600 uppercase tracking-widest mt-6">Next iteration in 30s</p>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Platform</label>
                        <select className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-medium" value={formData.platform} onChange={e => setFormData({...formData, platform: e.target.value})}>
                          <option value="4">MetaTrader 4</option>
                          <option value="5">MetaTrader 5</option>
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Display Label</label>
                        <input type="text" placeholder="e.g. Scalper-Node" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">MT Account ID</label>
                        <input type="text" placeholder="Digits only" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Server Address</label>
                        <input type="text" placeholder="e.g. IC MarketsSC-Live" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm font-mono" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
                      </div>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Master Password</label>
                      <input type="password" placeholder="••••••••" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white focus:border-indigo-500 outline-none text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                    </div>
                    <div className="flex gap-4 pt-4">
                      <button onClick={() => setIsAdding(false)} className="flex-1 py-4 text-slate-500 font-black uppercase tracking-widest text-[10px]">Discard</button>
                      <button onClick={handleCreateAccount} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-500 shadow-lg shadow-indigo-600/30 flex items-center justify-center gap-3">
                        {isSubmitting ? <Loader2 className="animate-spin w-4 h-4" /> : <Zap className="w-4 h-4" />} Initialize
                      </button>
                    </div>
                  </>
                )}
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {accounts.map(acc => (
              <div key={acc.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] backdrop-blur-sm group hover:border-indigo-500/30 transition-all shadow-xl">
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-indigo-600/10 rounded-xl flex items-center justify-center font-black text-indigo-400 group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-inner uppercase">{acc.platform}</div>
                    <div>
                      <h4 className="font-black text-white">{acc.name}</h4>
                      <p className="text-[10px] text-slate-500 font-mono tracking-tighter">{acc.login}</p>
                    </div>
                  </div>
                  <div className="flex flex-col items-end gap-1">
                    <div className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest border ${acc.connectionStatus === 'CONNECTED' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-slate-800 text-slate-500 border-white/5'}`}>{acc.connectionStatus}</div>
                    <div className="text-[7px] font-black text-slate-600 uppercase tracking-widest">{acc.state}</div>
                  </div>
                </div>

                <div className="bg-black/20 p-5 rounded-3xl border border-white/5 mb-6 grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">Node Lifecycle</p>
                    <div className="flex items-center gap-2">
                       {acc.state === 'UNDEPLOYED' || acc.state === 'FAILED' ? (
                         <button 
                           onClick={() => handleNodeAction(acc.id, 'deploy')} 
                           disabled={actionLoading === `${acc.id}-deploy`}
                           className="text-[9px] font-black text-indigo-400 hover:text-white flex items-center gap-1 transition-colors uppercase tracking-widest"
                         >
                           {actionLoading === `${acc.id}-deploy` ? <Loader2 className="w-2 h-2 animate-spin" /> : <Power className="w-3 h-3" />} Deploy
                         </button>
                       ) : (
                         <button 
                           onClick={() => handleNodeAction(acc.id, 'undeploy')} 
                           disabled={actionLoading === `${acc.id}-undeploy`}
                           className="text-[9px] font-black text-rose-500 hover:text-white flex items-center gap-1 transition-colors uppercase tracking-widest"
                         >
                           {actionLoading === `${acc.id}-undeploy` ? <Loader2 className="w-2 h-2 animate-spin" /> : <PowerOff className="w-3 h-3" />} Undeploy
                         </button>
                       )}
                       {acc.state === 'DEPLOYED' && (
                         <button 
                           onClick={() => handleNodeAction(acc.id, 'redeploy')}
                           disabled={actionLoading === `${acc.id}-redeploy`}
                           className="text-[9px] font-black text-emerald-400 hover:text-white flex items-center gap-1 transition-colors uppercase tracking-widest ml-2"
                         >
                           {actionLoading === `${acc.id}-redeploy` ? <Loader2 className="w-2 h-2 animate-spin" /> : <RefreshCw className="w-3 h-3" />} Redeploy
                         </button>
                       )}
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[8px] font-black text-slate-600 uppercase mb-1">Equity</p>
                    <p className="text-sm font-black text-white">${acc.balance?.toLocaleString() || '0.00'}</p>
                  </div>
                </div>

                <div className="flex gap-2">
                  <button onClick={() => generateConfigLink(acc.id)} className="p-4 bg-white/5 text-slate-400 hover:text-white rounded-xl border border-white/5 transition-all" title="Secure Link"><LinkIcon className="w-4 h-4" /></button>
                  <button onClick={() => { setEditingCredentials(acc); setFormData({...formData, name: acc.name, login: acc.login === 'PENDING' ? '' : acc.login, server: ''}); }} className="p-4 bg-white/5 text-slate-400 hover:text-white rounded-xl border border-white/5 transition-all" title="Edit Meta"><Pencil className="w-4 h-4" /></button>
                  <button onClick={() => handleNodeAction(acc.id, 'redeploy')} className="flex-1 bg-white/5 hover:bg-indigo-600 text-indigo-400 hover:text-white py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/5">Maintenance Sync</button>
                  <button onClick={() => handleDeleteAccount(acc.id)} className="p-4 bg-rose-500/10 text-rose-500 rounded-xl border border-rose-500/20 transition-all hover:bg-rose-500 hover:text-white"><Trash2 className="w-4 h-4" /></button>
                </div>
              </div>
            ))}
          </div>

          {editingCredentials && (
            <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
               <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-lg w-full shadow-2xl space-y-6">
                 <div className="flex justify-between items-center border-b border-white/5 pb-6">
                    <div className="flex items-center gap-3">
                      <Settings2 className="w-5 h-5 text-indigo-400" />
                      <h3 className="text-lg font-black text-white uppercase tracking-widest">Update Node Definition</h3>
                    </div>
                    <button onClick={() => setEditingCredentials(null)} className="text-slate-500 hover:text-white"><X /></button>
                 </div>
                 <div className="space-y-4">
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">Node Name</label>
                     <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">MT Login ID</label>
                     <input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-mono" value={formData.login} onChange={e => setFormData({...formData, login: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">New Password</label>
                     <input type="password" placeholder="••••••••" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest ml-2">Broker Server</label>
                     <input type="text" placeholder="Exact server name" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm font-mono" value={formData.server} onChange={e => setFormData({...formData, server: e.target.value})} />
                   </div>
                 </div>
                 <div className="flex gap-4 pt-6 border-t border-white/5">
                   <button onClick={() => setEditingCredentials(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-[10px]">Discard</button>
                   <button onClick={handleUpdateAccountFull} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase transition-all hover:bg-indigo-500 shadow-lg shadow-indigo-600/30 flex items-center justify-center gap-3">
                     {isSubmitting ? <Loader2 className="animate-spin w-4 h-4" /> : <RefreshCw className="w-4 h-4" />} Update & Redeploy
                   </button>
                 </div>
                 <p className="text-[8px] text-slate-600 text-center uppercase tracking-widest">A hardware redeploy is triggered upon update</p>
               </div>
            </div>
          )}
        </>
      ) : (
        <div className="space-y-6">
          <div className="grid grid-cols-1 gap-4">
            {profiles.length === 0 && (
              <div className="py-20 bg-slate-900/20 border border-dashed border-white/5 rounded-[40px] flex flex-col items-center justify-center text-center">
                <Globe className="w-12 h-12 text-slate-800 mb-4" />
                <p className="text-slate-600 text-[10px] font-black uppercase tracking-widest">No Terminal Frameworks Found</p>
              </div>
            )}
            {profiles.map(p => {
              const usageCount = getUsageCount(p.id || p._id || '');
              return (
                <div key={p.id || p._id} className="bg-slate-900/40 border border-white/5 p-6 rounded-[32px] flex items-center justify-between group hover:border-indigo-500/20 transition-all">
                  <div className="flex items-center gap-6">
                    <div className="w-12 h-12 bg-slate-950 rounded-2xl flex items-center justify-center border border-white/5 text-slate-500 font-black group-hover:text-indigo-400 transition-colors uppercase">MT{p.version}</div>
                    <div>
                      <h4 className="text-sm font-black text-white tracking-tight">{p.name}</h4>
                      <div className="flex items-center gap-3 mt-1 text-[9px] font-black text-slate-500 uppercase tracking-widest">
                        <span>{p.brokerTimezone}</span>
                        <span className="w-1 h-1 rounded-full bg-slate-800"></span>
                        <span className={usageCount > 0 ? 'text-indigo-400 font-bold' : 'text-slate-600'}>Active Nodes: {usageCount}</span>
                        <span className="w-1 h-1 rounded-full bg-slate-800"></span>
                        <span className={p.status === 'new' ? 'text-amber-500' : 'text-indigo-400'}>{p.status}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setEditingProfile(p)} className="p-3 hover:bg-indigo-500/10 text-slate-500 hover:text-indigo-400 rounded-xl transition-all"><Settings2 className="w-5 h-5" /></button>
                    <button 
                      onClick={() => handleDeleteProfile(p.id || p._id || '')} 
                      className={`p-3 rounded-xl transition-all ${usageCount > 0 ? 'opacity-20 cursor-not-allowed' : 'hover:bg-rose-500/10 text-slate-500 hover:text-rose-500'}`}
                      disabled={usageCount > 0}
                      title={usageCount > 0 ? "Blocked: Node Dependency" : "Destroy Framework"}
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>

          {editingProfile && (
            <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
              <div className="bg-slate-950 border border-white/10 rounded-[40px] p-10 max-w-lg w-full shadow-2xl space-y-6">
                <div className="flex justify-between items-center"><h3 className="text-lg font-black text-white uppercase tracking-widest tracking-tight">Modify Framework</h3><button onClick={() => setEditingProfile(null)} className="text-slate-500 hover:text-white"><X /></button></div>
                <div className="space-y-4">
                   <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Profile Label</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.name} onChange={e => setEditingProfile({...editingProfile, name: e.target.value})} /></div>
                   <div className="grid grid-cols-2 gap-4">
                     <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">Timezone</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.brokerTimezone} onChange={e => setEditingProfile({...editingProfile, brokerTimezone: e.target.value})} /></div>
                     <div><label className="text-[10px] font-bold text-slate-500 uppercase ml-2 tracking-widest">DST Policy</label><input type="text" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3.5 text-white outline-none focus:border-indigo-500 text-sm" value={editingProfile.brokerDSTSwitchTimezone} onChange={e => setEditingProfile({...editingProfile, brokerDSTSwitchTimezone: e.target.value})} /></div>
                   </div>
                   <div className="pt-4">
                     <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".dat,.ini,.srv" />
                     <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-white/5 border border-white/5 rounded-xl text-[10px] font-black uppercase text-indigo-400 hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-3"><Upload className="w-4 h-4" /> Update Server Sync</button>
                   </div>
                </div>
                <div className="flex gap-4 pt-6 border-t border-white/5">
                  <button onClick={() => setEditingProfile(null)} className="flex-1 py-4 text-slate-500 font-black uppercase text-[10px]">Discard</button>
                  <button onClick={handleUpdateProfile} disabled={isSubmitting} className="flex-[2] bg-indigo-600 text-white py-4 px-8 rounded-xl font-black text-[10px] uppercase transition-all hover:bg-indigo-500 shadow-lg shadow-indigo-600/30 flex items-center justify-center gap-3">
                    {isSubmitting ? <Loader2 className="animate-spin w-4 h-4" /> : <ShieldCheck className="w-4 h-4" />} Commit Changes
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

