import React, { useState } from 'react';
import { Layers, Play, CheckCircle, AlertCircle, Copy, ArrowRight, Terminal, Loader2, ShieldCheck, Zap } from 'lucide-react';
import { TradingAccount } from '../types';

interface CopyFactoryConfigProps {
  accounts: TradingAccount[];
}

const CopyFactoryConfig: React.FC<CopyFactoryConfigProps> = ({ accounts }) => {
  const [status, setStatus] = useState<'idle' | 'configuring' | 'success' | 'error'>('idle');
  const [providerId, setProviderId] = useState(accounts[0]?.id || '');
  const [subscriberId, setSubscriberId] = useState(accounts[1]?.id || '');
  const [log, setLog] = useState<string[]>([]);

  const addLog = (msg: string) => setLog(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  const getRawToken = () => {
    const raw = (process.env.API_KEY || '').trim();
    return raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
  };

  const handleConfigure = async () => {
    if (!providerId || !subscriberId) {
      alert("Please select both a Master Provider and a Subscriber Node.");
      return;
    }

    if (providerId === subscriberId) {
      alert("Source and Destination nodes must be different.");
      return;
    }

    setStatus('configuring');
    setLog([]);
    addLog(`Initiating London cluster copy engine sync...`);

    const TOKEN = getRawToken();
    const PROVISIONING_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';
    const COPYFACTORY_BASE = 'https://copyfactory-api-v1.london.agiliumtrade.ai';

    const getHeaders = () => ({
      'auth-token': TOKEN,
      'Accept': 'application/json',
      'Content-Type': 'application/json'
    });

    try {
      // STEP 1: Enable CopyFactory API for Provider
      addLog(`Activating PROVIDER role for master node...`);
      const enableProvRes = await fetch(`${PROVISIONING_BASE}/users/current/accounts/${providerId}/enable-copy-factory-api`, {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          copyFactoryRoles: ["PROVIDER"],
          copyFactoryResourceSlots: 1
        })
      });

      if (!enableProvRes.ok && enableProvRes.status !== 204) {
        const err = await enableProvRes.json();
        throw new Error(`Master Activation Failed: ${err.message}`);
      }
      addLog(`Master Node activated (PROVIDER mode).`);

      // STEP 2: Enable CopyFactory API for Subscriber
      addLog(`Activating SUBSCRIBER role for destination node...`);
      const enableSubRes = await fetch(`${PROVISIONING_BASE}/users/current/accounts/${subscriberId}/enable-copy-factory-api`, {
        method: 'POST',
        headers: getHeaders(),
        body: JSON.stringify({
          copyFactoryRoles: ["SUBSCRIBER"],
          copyFactoryResourceSlots: 1
        })
      });

      if (!enableSubRes.ok && enableSubRes.status !== 204) {
        const err = await enableSubRes.json();
        throw new Error(`Subscriber Activation Failed: ${err.message}`);
      }
      addLog(`Subscriber Node activated (SUBSCRIBER mode).`);

      // STEP 3: Generate Strategy Node in CopyFactory
      addLog(`Generating Strategy Node on London cluster...`);
      const strategyIdRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/generate-strategy-id`, {
        method: 'POST',
        headers: getHeaders()
      });

      if (!strategyIdRes.ok) throw new Error("CopyFactory strategy generation failed.");
      const strategyData = await strategyIdRes.json();
      const sid = strategyData.id || strategyData._id;

      // STEP 4: Configure Strategy
      addLog(`Mapping account ${providerId.slice(-4)} to Strategy ${sid.slice(-4)}...`);
      const putStratRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/strategies/${sid}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ 
          name: `Master-Sync-${providerId.slice(-4)}`, 
          accountId: providerId 
        })
      });
      if (!putStratRes.ok) throw new Error("Strategy configuration PUT failed.");

      // STEP 5: Attach Subscriber
      addLog(`Binding Subscriber to Strategy...`);
      const subRes = await fetch(`${COPYFACTORY_BASE}/users/current/configuration/subscribers/${subscriberId}`, {
        method: 'PUT',
        headers: getHeaders(),
        body: JSON.stringify({ 
          name: `Sub-Node-${subscriberId.slice(-4)}`,
          subscriptions: [{ strategyId: sid, multiplier: 1 }] 
        })
      });

      if (!subRes.ok) throw new Error("Subscriber attachment rejected by CopyFactory.");

      setStatus('success');
      addLog(`SUCCESS: Sync pipeline active on London Cluster.`);
      addLog(`Note: Accounts may temporarily stop/restart during initial role binding.`);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      addLog(`FATAL: ${err.message}`);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900/40 border border-white/5 rounded-[40px] p-10 shadow-2xl backdrop-blur-md">
        <div className="flex items-center justify-between mb-10">
          <div className="flex items-center gap-5">
            <div className="w-14 h-14 bg-indigo-600/10 rounded-2xl flex items-center justify-center border border-indigo-500/20">
              <Layers className="text-indigo-400 w-7 h-7" />
            </div>
            <div>
              <h2 className="text-2xl font-black text-white tracking-tight">Copy Engine</h2>
              <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest mt-1">Gateway: copyfactory-v2.london</p>
            </div>
          </div>
          <div className="flex items-center gap-2 px-4 py-2 bg-amber-500/10 border border-amber-500/20 rounded-xl">
            <ShieldCheck className="w-4 h-4 text-amber-500" />
            <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest">Paid Option Active</span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-center mb-10 bg-slate-950/50 p-8 rounded-[32px] border border-white/5">
          <div className="space-y-4">
            <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <Zap className="w-3 h-3 text-indigo-500" /> Master Provider
            </label>
            <select 
              value={providerId} 
              onChange={(e) => setProviderId(e.target.value)} 
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-4 text-white outline-none focus:border-indigo-500 text-sm font-bold"
            >
              <option value="" disabled>Select Source</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
          <div className="flex justify-center pt-6">
            <div className="w-12 h-12 rounded-full bg-indigo-500/10 border border-indigo-500/20 flex items-center justify-center">
              <ArrowRight className="text-indigo-400 w-5 h-5 animate-pulse" />
            </div>
          </div>
          <div className="space-y-4">
            <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
              <LayoutDashboard className="w-3 h-3 text-indigo-500" /> Subscriber Node
            </label>
            <select 
              value={subscriberId} 
              onChange={(e) => setSubscriberId(e.target.value)} 
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-4 text-white outline-none focus:border-indigo-500 text-sm font-bold"
            >
              <option value="" disabled>Select Target</option>
              {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name} ({acc.login})</option>)}
            </select>
          </div>
        </div>

        <div className="flex flex-col gap-4">
          <button 
            onClick={handleConfigure} 
            disabled={status === 'configuring' || accounts.length < 2} 
            className="w-full py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-4 bg-indigo-600 hover:bg-indigo-500 text-white transition-all shadow-lg shadow-indigo-600/30 disabled:opacity-50 disabled:cursor-not-allowed group"
          >
            {status === 'configuring' ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : (
              <Play className="w-5 h-5 group-hover:scale-125 transition-transform" />
            )}
            {status === 'configuring' ? 'Configuring London Cluster...' : 'Enable London Copy Sync'}
          </button>
          <p className="text-center text-[8px] text-slate-600 uppercase tracking-widest">
            By enabling sync, you acknowledge that CopyFactory resource slots are billed as a paid infrastructure upgrade.
          </p>
        </div>
      </div>

      <div className="bg-slate-900/40 border border-white/5 rounded-[32px] p-8 h-72 overflow-y-auto font-mono text-[10px] text-slate-400 custom-scrollbar shadow-inner backdrop-blur-sm border-t-2 border-t-indigo-500/30">
        <div className="flex items-center gap-2 mb-4">
          <Terminal className="w-4 h-4 text-indigo-500" />
          <div className="text-indigo-500/50 font-black tracking-widest uppercase">-- ENGINE_LOG::REGION_LONDON --</div>
        </div>
        {log.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full opacity-20">
            <p className="uppercase tracking-[0.3em]">Standby for signal sync...</p>
          </div>
        ) : (
          log.map((line, i) => (
            <div key={i} className={`mb-1.5 border-l-2 pl-3 py-0.5 transition-all ${
              line.includes('SUCCESS') ? 'border-emerald-500 text-emerald-400' : 
              line.includes('FATAL') ? 'border-rose-500 text-rose-500' : 'border-indigo-500/20'
            }`}>
              {line}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

