import React, { useState, useCallback, useRef, useEffect } from 'react';
import { TradingAccount, PlatformType, ExpertAdvisor } from '../types';
import { 
  Trash2, Server, Zap, Loader2, Info, ShieldCheck, 
  Upload, FileCheck, AlertTriangle, Settings2, Database,
  ChevronRight, Pencil, X, Globe, Key, RefreshCw, Power, PowerOff, Link as LinkIcon,
  Cpu, Activity, FileCode, CheckCircle2
} from 'lucide-react';

interface AccountConfigProps {
  accounts: TradingAccount[];
  setAccounts: React.Dispatch<React.SetStateAction<TradingAccount[]>>;
}

interface ProvisioningProfile {
  _id?: string;
  id?: string;
  name: string;
  version: number;
  status: string;
  brokerTimezone: string;
  brokerDSTSwitchTimezone: string;
  type: string;
}

const AccountConfig: React.FC<AccountConfigProps> = ({ accounts, setAccounts }) => {
  const [view, setView] = useState<'accounts' | 'profiles'>('accounts');
  const [isAdding, setIsAdding] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [profiles, setProfiles] = useState<ProvisioningProfile[]>([]);
  const [activeStep, setActiveStep] = useState<'idle' | 'profile-check' | 'profile-create' | 'upload-file' | 'account-link' | 'polling'>('idle');
  const [editingProfile, setEditingProfile] = useState<ProvisioningProfile | null>(null);
  const [editingCredentials, setEditingCredentials] = useState<TradingAccount | null>(null);
  const [inspectingAccount, setInspectingAccount] = useState<TradingAccount | null>(null);
  const [expertAdvisors, setExpertAdvisors] = useState<ExpertAdvisor[]>([]);
  const [loadingEAs, setLoadingEAs] = useState(false);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [pollingMessage, setPollingMessage] = useState<string>('');

  const [formData, setFormData] = useState({ 
    name: '', 
    platform: '4', 
    login: '', 
    password: '', 
    server: '',
    timezone: 'EET',
    dstTimezone: 'EET'
  });

  const [pendingProfileId, setPendingProfileId] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const API_BASE = 'https://mt-provisioning-api-v1.agiliumtrade.agiliumtrade.ai';

  const generateTransactionId = () => {
    return Array.from({ length: 32 }, () => Math.floor(Math.random() * 16).toString(16)).join('');
  };

  const getAuthHeader = useCallback(() => {
    const raw = (process.env.API_KEY || '').trim();
    const cleanToken = raw.replace(/^['"]|['"]$/g, '').replace(/bearer/gi, '').trim();
    return {
      'auth-token': cleanToken,
      'Accept': 'application/json'
    };
  }, []);

  const fetchProfiles = useCallback(async () => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      if (res.ok) {
        const data = await res.json();
        setProfiles(data);
      }
    } catch (err) {
      console.error("Failed to fetch profiles:", err);
    }
  }, [getAuthHeader]);

  const fetchExpertAdvisors = async (accountId: string) => {
    setLoadingEAs(true);
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${accountId}/expert-advisors`, { headers });
      if (res.ok) {
        const data = await res.json();
        setExpertAdvisors(data);
      }
    } catch (err) {
      console.error("Failed to fetch EAs:", err);
    } finally {
      setLoadingEAs(false);
    }
  };

  useEffect(() => {
    fetchProfiles();
  }, [fetchProfiles]);

  const handleNodeAction = async (accountId: string, action: 'deploy' | 'undeploy' | 'redeploy') => {
    setActionLoading(`${accountId}-${action}`);
    const headers = getAuthHeader();
    try {
      const url = action === 'deploy' 
        ? `${API_BASE}/users/current/accounts/${accountId}/deploy?executeForAllReplicas=true`
        : `${API_BASE}/users/current/accounts/${accountId}/${action}`;

      const res = await fetch(url, {
        method: 'POST',
        headers
      });

      if (!res.ok && res.status !== 204) {
        const err = await res.json();
        throw new Error(err.message || `Action ${action} failed.`);
      }

      alert(`Node ${action} sequence initiated successfully.`);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setActionLoading(null);
    }
  };

  const generateConfigLink = async (accountId: string) => {
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${accountId}/configuration-link?ttlInDays=7`, {
        method: 'PUT',
        headers
      });
      if (res.ok) {
        const data = await res.json();
        const url = data.configurationLink;
        if (confirm(`Secure configuration link generated:\n\n${url}\n\nCopy to clipboard?`)) {
          navigator.clipboard.writeText(url);
        }
      }
    } catch (err) {
      alert("Failed to generate configuration link.");
    }
  };

  const handleCreateAccount = async () => {
    if (!formData.name || !formData.server) {
      alert("Account Name and Server are required for provisioning.");
      return;
    }

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const transactionId = generateTransactionId();

    try {
      setActiveStep('profile-check');
      const profileName = `PROFILE-${formData.server.replace(/[^a-zA-Z0-9]/g, '-')}-${formData.platform}`;

      const listRes = await fetch(`${API_BASE}/users/current/provisioning-profiles?type=mtTerminal`, { headers });
      const existingProfiles = await listRes.json();
      let profileId = existingProfiles.find((p: any) => p.name === profileName)?._id || existingProfiles.find((p: any) => p.name === profileName)?.id;

      if (!profileId) {
        setActiveStep('profile-create');
        const createRes = await fetch(`${API_BASE}/users/current/provisioning-profiles`, {
          method: 'POST',
          headers: { ...headers, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: profileName,
            version: parseInt(formData.platform),
            brokerTimezone: formData.timezone,
            brokerDSTSwitchTimezone: formData.dstTimezone,
            type: 'mtTerminal'
          })
        });

        if (!createRes.ok) throw new Error("Failed to initialize cloud infrastructure.");
        const newProfile = await createRes.json();
        profileId = newProfile.id || newProfile._id;

        setPendingProfileId(profileId);
        setActiveStep('upload-file');
        setIsSubmitting(false);
        return;
      }

      await executeProvisioning(profileId, transactionId);
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const executeProvisioning = async (profileId: string, transactionId: string) => {
    setActiveStep('account-link');
    setIsSubmitting(true);
    const headers = getAuthHeader();

    const payload: any = {
      name: formData.name,
      server: formData.server,
      magic: 10101,
      provisioningProfileId: profileId,
      reliability: 'high',
      region: 'london',
      type: 'cloud-g2'
    };

    if (formData.login) payload.login = formData.login;
    if (formData.password) payload.password = formData.password;
    if (!profileId) payload.platform = formData.platform === '5' ? 'mt5' : 'mt4';

    try {
      const response = await fetch(`${API_BASE}/users/current/accounts`, {
        method: 'POST',
        headers: { 
          ...headers, 
          'Content-Type': 'application/json',
          'transaction-id': transactionId
        },
        body: JSON.stringify(payload)
      });

      if (response.status === 202) {
        const data = await response.json();
        setPollingMessage(data.message || "Automatic broker settings detection in progress...");
        setActiveStep('polling');

        setTimeout(() => executeProvisioning(profileId, transactionId), 30000);
        return;
      }

      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.message || "Onboarding rejected by gateway.");
      }

      const newAccount = await response.json();
      setAccounts(prev => [...prev, {
        id: newAccount.id || newAccount._id,
        name: formData.name,
        platform: formData.platform === '5' ? PlatformType.MT5 : PlatformType.MT4,
        login: formData.login || 'PENDING',
        connectionStatus: 'DISCONNECTED',
        state: newAccount.state || 'UNDEPLOYED',
        balance: 0,
        equity: 0
      }]);

      setIsAdding(false);
      setActiveStep('idle');
      setPendingProfileId(null);
      setIsSubmitting(false);
      fetchProfiles();
    } catch (err: any) {
      alert(err.message);
      setIsSubmitting(false);
      setActiveStep('idle');
    }
  };

  const handleUpdateAccountFull = async () => {
    if (!editingCredentials) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingCredentials.id;

    try {
      const updateRes = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: formData.name,
          server: formData.server,
          password: formData.password,
          manualTrades: false,
          magic: 10101
        })
      });

      if (!updateRes.ok && updateRes.status !== 204) {
        const err = await updateRes.json();
        throw new Error(err.message || "Account update rejected.");
      }

      await fetch(`${API_BASE}/users/current/accounts/${id}/credentials`, {
        method: 'PUT',
        headers: { ...headers, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          login: formData.login,
          password: formData.password,
          serverName: formData.server
        })
      });

      alert("Configuration synced. Hardware redeploy required.");
      await handleNodeAction(id, 'redeploy');
      setEditingCredentials(null);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteAccount = async (id: string) => {
    if (!confirm("Remove node from cluster? All cloud resources will be released.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/accounts/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.ok) {
        setAccounts(prev => prev.filter(a => a.id !== id));
      }
    } catch (err) {
      alert("Node deletion failed.");
    }
  };

  const handleDeleteProfile = async (id: string) => {
    if (!confirm("Destroy infrastructure profile? Node dependencies must be zero.")) return;
    const headers = getAuthHeader();
    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
        method: 'DELETE',
        headers
      });
      if (res.status === 400) {
        alert("Infrastructure Error: This profile is actively used by trading nodes.");
        return;
      }
      if (res.ok) {
        fetchProfiles();
      }
    } catch (err) {
      alert("Failed to destroy profile.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const targetId = pendingProfileId || (editingProfile?.id || editingProfile?._id);
    if (!file || !targetId) return;

    setIsSubmitting(true);
    const headers = getAuthHeader();
    const version = editingProfile ? editingProfile.version : parseInt(formData.platform);
    const expectedName = version === 5 ? 'servers.dat' : (file.name.endsWith('.ini') ? 'servers.ini' : 'broker.srv');

    const body = new FormData();
    body.append('file', file);

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${targetId}/${expectedName}`, {
        method: 'PUT',
        headers: { 'auth-token': headers['auth-token'] },
        body: body
      });
      if (!res.ok) throw new Error("Terminal file synchronization failed.");

      if (pendingProfileId) {
        const transactionId = generateTransactionId();
        await executeProvisioning(pendingProfileId, transactionId);
      } else {
        alert("Cloud configuration updated.");
        fetchProfiles();
      }
    } catch (err: any) {
      alert(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleUpdateProfile = async () => {
    if (!editingProfile) return;
    setIsSubmitting(true);
    const headers = getAuthHeader();
    const id = editingProfile.id || editingProfile._id;

    try {
      const res = await fetch(`${API_BASE}/users/current/provisioning-profiles/${id}`, {
